/**
 * AuditChain — Phase 7: Merkle Hash Chain
 *
 * Append-only log con hash encadenado para auditabilidad tamper-evident.
 * Cada mutación genera un AuditEntry con SHA-256 encadenado.
 */

import * as fs from 'fs/promises';
import { createHash } from 'crypto';
import { existsSync, createWriteStream, WriteStream } from 'fs';

export interface AuditEntry {
    sequence: number;
    timestamp: number;
    actor: string;
    action: string;
    target: string;
    payload: string;
    prevHash: string;
    hash: string;
}

export interface MerkleCheckpoint {
    sequence: number;
    timestamp: number;
    merkleRoot: string;
    batchSize: number;
}

export interface AuditChainConfig {
    filePath: string;
    checkpointInterval?: number; // default: 1000
}

function sha256(input: string): string {
    return createHash('sha256').update(input, 'utf8').digest('hex');
}

function computeEntryHash(entry: Omit<AuditEntry, 'hash'>): string {
    const canonical = [
        entry.sequence,
        entry.timestamp,
        entry.actor,
        entry.action,
        entry.target,
        entry.payload,
        entry.prevHash,
    ].join('|');
    return sha256(canonical);
}

function computeMerkleRoot(hashes: string[]): string {
    if (hashes.length === 0) return sha256('');
    if (hashes.length === 1) return hashes[0];

    const nextLevel: string[] = [];
    for (let i = 0; i < hashes.length; i += 2) {
        const left = hashes[i];
        const right = i + 1 < hashes.length ? hashes[i + 1] : left;
        nextLevel.push(sha256(left + right));
    }
    return computeMerkleRoot(nextLevel);
}

export class AuditChain {
    private readonly filePath: string;
    private readonly checkpointPath: string;
    private readonly checkpointInterval: number;
    private writeStream: WriteStream | null = null;
    private sequence = 0;
    private prevHash = '';
    private batchHashes: string[] = [];
    private initPromise: Promise<void> | null = null;
    private totalEntries = 0;
    private lastVerifyResult: { valid: boolean; corrupted: number[] } | null = null;

    constructor(config: AuditChainConfig) {
        this.filePath = config.filePath;
        this.checkpointPath = `${config.filePath}.ckpt`;
        this.checkpointInterval = config.checkpointInterval ?? 1000;
    }

    async initialize(): Promise<void> {
        if (this.initPromise) return this.initPromise;
        this.initPromise = this._initialize();
        return this.initPromise;
    }

    private async _initialize(): Promise<void> {
        if (existsSync(this.filePath)) {
            const raw = await fs.readFile(this.filePath, 'utf8');
            const lines = raw.split('\n').map(l => l.trim()).filter(Boolean);
            this.totalEntries = 0;
            for (const line of lines) {
                try {
                    const entry = JSON.parse(line) as AuditEntry;
                    this.totalEntries++;
                    if (entry.sequence > this.sequence) {
                        this.sequence = entry.sequence;
                        this.prevHash = entry.hash;
                    }
                } catch {
                    // Corrupted line, skip
                }
            }
        }

        this.writeStream = createWriteStream(this.filePath, { flags: 'a' });
    }

    async append(
        actor: string,
        action: string,
        target: string,
        payload: Record<string, any>
    ): Promise<AuditEntry> {
        await this.initialize();

        const payloadStr = JSON.stringify(payload);
        const payloadHash = payloadStr.length > 1024 ? sha256(payloadStr) : payloadStr;

        const entry: Omit<AuditEntry, 'hash'> = {
            sequence: ++this.sequence,
            timestamp: Date.now(),
            actor,
            action,
            target,
            payload: payloadHash,
            prevHash: this.prevHash,
        };

        const hash = computeEntryHash(entry);
        const fullEntry: AuditEntry = { ...entry, hash };

        this.prevHash = hash;
        this.batchHashes.push(hash);
        this.totalEntries++;

        return new Promise((resolve, reject) => {
            this.writeStream!.write(JSON.stringify(fullEntry) + '\n', (err) => {
                if (err) return reject(err);
                this.maybeCheckpoint().catch(() => {}); // Best-effort
                resolve(fullEntry);
            });
        });
    }

    private async maybeCheckpoint(): Promise<void> {
        if (this.batchHashes.length < this.checkpointInterval) return;

        const merkleRoot = computeMerkleRoot(this.batchHashes);
        const checkpoint: MerkleCheckpoint = {
            sequence: this.sequence,
            timestamp: Date.now(),
            merkleRoot,
            batchSize: this.batchHashes.length,
        };

        await fs.appendFile(this.checkpointPath, JSON.stringify(checkpoint) + '\n', 'utf8');
        this.batchHashes = [];
    }

    async verify(): Promise<{ valid: boolean; totalEntries: number; corrupted: number[]; chainBroken: boolean }> {
        await this.initialize();

        if (!existsSync(this.filePath)) {
            return { valid: true, totalEntries: 0, corrupted: [], chainBroken: false };
        }

        const raw = await fs.readFile(this.filePath, 'utf8');
        const lines = raw.split('\n').map(l => l.trim()).filter(Boolean);

        let expectedPrevHash = '';
        const corrupted: number[] = [];
        let chainBroken = false;

        for (const line of lines) {
            try {
                const entry = JSON.parse(line) as AuditEntry;
                const recomputed = computeEntryHash({
                    sequence: entry.sequence,
                    timestamp: entry.timestamp,
                    actor: entry.actor,
                    action: entry.action,
                    target: entry.target,
                    payload: entry.payload,
                    prevHash: entry.prevHash,
                });

                if (recomputed !== entry.hash) {
                    corrupted.push(entry.sequence);
                }

                if (entry.prevHash !== expectedPrevHash) {
                    chainBroken = true;
                }

                expectedPrevHash = entry.hash;
            } catch {
                // Invalid JSON, skip
            }
        }

        const result = {
            valid: corrupted.length === 0 && !chainBroken,
            totalEntries: lines.length,
            corrupted,
            chainBroken,
        };
        this.lastVerifyResult = { valid: result.valid, corrupted: [...result.corrupted] };
        return result;
    }

    getQuickStats(): { totalEntries: number; lastVerifyValid: boolean | null } {
        return {
            totalEntries: this.totalEntries,
            lastVerifyValid: this.lastVerifyResult?.valid ?? null,
        };
    }

    async export(): Promise<string[]> {
        await this.initialize();

        if (!existsSync(this.filePath)) return [];

        const raw = await fs.readFile(this.filePath, 'utf8');
        return raw.split('\n').map(l => l.trim()).filter(Boolean);
    }

    async close(): Promise<void> {
        if (!this.writeStream) return;
        return new Promise((resolve) => {
            this.writeStream!.end(() => {
                this.writeStream = null;
                resolve();
            });
        });
    }
}

import * as fs from 'node:fs/promises';
import { randomBytes } from 'node:crypto';
import { wait } from '../gics-utils.js';

/**
 * Lock mode supported by the daemon.
 */
export type FileLockMode = 'shared' | 'exclusive';

export class FileLockTimeoutError extends Error {
    constructor(filePath: string, mode: FileLockMode, timeoutMs: number) {
        super(`Failed to acquire ${mode} lock for ${filePath} within ${timeoutMs}ms.`);
        this.name = 'FileLockTimeoutError';
    }
}

/**
 * In-process async read-write lock. FIFO queue, write-preferring.
 *
 * Write-preferring: when an exclusive waiter is queued, no new shared
 * grants are issued until the exclusive completes. This prevents writer
 * starvation under continuous reader load.
 *
 * Single-threaded event loop guarantees: no TOCTOU races, no atomicity
 * concerns. The queue drains synchronously after each release().
 */
export class AsyncRWLock {
    private readers = 0;
    private writer = false;
    private readonly queue: { mode: FileLockMode; resolve: () => void }[] = [];

    async acquire(mode: FileLockMode, timeoutMs: number = 5000): Promise<void> {
        // Fast path: immediate grant if no contention and no exclusive waiter.
        if (mode === 'shared' && !this.writer && !this.hasExclusiveWaiter()) {
            this.readers++;
            return;
        }
        if (mode === 'exclusive' && !this.writer && this.readers === 0) {
            this.writer = true;
            return;
        }

        // Slow path: enqueue and wait.
        return new Promise<void>((resolve, reject) => {
            const entry = { mode, resolve: () => { /* replaced below */ } };
            this.queue.push(entry);

            const timer = setTimeout(() => {
                const idx = this.queue.indexOf(entry);
                if (idx !== -1) {
                    this.queue.splice(idx, 1);
                    reject(new FileLockTimeoutError('(in-process)', mode, timeoutMs));
                }
            }, timeoutMs);

            entry.resolve = () => {
                clearTimeout(timer);
                resolve();
            };
        });
    }

    release(): void {
        if (this.writer) {
            this.writer = false;
        } else if (this.readers > 0) {
            this.readers--;
        }
        this.drain();
    }

    private hasExclusiveWaiter(): boolean {
        for (const w of this.queue) {
            if (w.mode === 'exclusive') return true;
        }
        return false;
    }

    private drain(): void {
        while (this.queue.length > 0) {
            const next = this.queue[0];
            if (next.mode === 'exclusive') {
                if (this.readers === 0 && !this.writer) {
                    this.queue.shift()!;
                    this.writer = true;
                    next.resolve();
                }
                return; // Exclusive waiter blocks all subsequent grants.
            } else if (this.writer) {
                return;
            } else {
                this.queue.shift()!;
                this.readers++;
                next.resolve();
                // Continue — grant consecutive shared waiters.
            }
        }
    }
}

/**
 * File-based locking for cross-platform environments (Node stdlib only).
 *
 * Instance API (acquire/release): marker-file based, for cross-process safety.
 * Static API (withExclusiveLock/withSharedLock): in-process AsyncRWLock per path,
 * race-free and zero-cost. Used by the daemon for all operations.
 */
export class FileLock {
    private readonly targetFilePath: string;
    private readonly lockDirPath: string;
    private readonly exclusiveLockPath: string;
    private heldMode: FileLockMode | null = null;
    private sharedLockPath: string | null = null;

    /** Per-path in-process locks for the static helpers. */
    private static readonly processLocks = new Map<string, AsyncRWLock>();

    private static getProcessLock(path: string): AsyncRWLock {
        let lock = FileLock.processLocks.get(path);
        if (!lock) {
            lock = new AsyncRWLock();
            FileLock.processLocks.set(path, lock);
        }
        return lock;
    }

    constructor(targetFilePath: string) {
        this.targetFilePath = targetFilePath;
        this.lockDirPath = `${targetFilePath}.locks`;
        this.exclusiveLockPath = `${this.lockDirPath}/exclusive.lock`;
    }

    private async ensureLockDir(): Promise<void> {
        await fs.mkdir(this.lockDirPath, { recursive: true });
    }

    private async writeLockFile(filePath: string, metadata: Record<string, string | number>): Promise<void> {
        const lockPayload = JSON.stringify(metadata);
        const handle = await fs.open(filePath, 'wx');
        try {
            await handle.writeFile(lockPayload, 'utf8');
        } finally {
            await handle.close();
        }
    }

    private async getSharedLockFiles(): Promise<string[]> {
        try {
            const files = await fs.readdir(this.lockDirPath);
            return files.filter((name) => name.startsWith('shared-') && name.endsWith('.lock'));
        } catch (err: any) {
            if (err.code === 'ENOENT') return [];
            throw err;
        }
    }

    private async existsExclusiveLock(): Promise<boolean> {
        try {
            await fs.access(this.exclusiveLockPath);
            return true;
        } catch (err: any) {
            if (err.code === 'ENOENT') return false;
            throw err;
        }
    }

    private async tryAcquireShared(): Promise<boolean> {
        if (await this.existsExclusiveLock()) {
            return false;
        }

        await this.ensureLockDir();
        const candidatePath = `${this.lockDirPath}/shared-${process.pid}-${Date.now()}-${randomBytes(4).toString('hex')}.lock`;

        try {
            await this.writeLockFile(candidatePath, {
                mode: 'shared',
                pid: process.pid,
                acquiredAt: Date.now()
            });
        } catch (err: any) {
            if (err.code === 'EEXIST') {
                return false;
            }
            throw err;
        }

        // Re-check after creation to close race with exclusive acquirer.
        if (await this.existsExclusiveLock()) {
            await fs.unlink(candidatePath).catch(() => undefined);
            return false;
        }

        this.heldMode = 'shared';
        this.sharedLockPath = candidatePath;
        return true;
    }

    private async tryAcquireExclusive(): Promise<boolean> {
        await this.ensureLockDir();

        try {
            await this.writeLockFile(this.exclusiveLockPath, {
                mode: 'exclusive',
                pid: process.pid,
                acquiredAt: Date.now()
            });
        } catch (err: any) {
            if (err.code === 'EEXIST') {
                return false;
            }
            throw err;
        }

        // Re-check shared readers to close race windows.
        const sharedFiles = await this.getSharedLockFiles();
        if (sharedFiles.length > 0) {
            await fs.unlink(this.exclusiveLockPath).catch(() => undefined);
            return false;
        }

        this.heldMode = 'exclusive';
        this.sharedLockPath = null;
        return true;
    }

    /**
     * Acquire a lock with timeout/retry policy. (Instance API — file-based)
     */
    async acquire(mode: FileLockMode, timeoutMs: number = 5000, retryIntervalMs: number = 100): Promise<void> {
        if (this.heldMode) {
            throw new Error(`Lock for ${this.targetFilePath} is already held in mode=${this.heldMode}.`);
        }

        const startTime = Date.now();

        while (Date.now() - startTime < timeoutMs) {
            const acquired = mode === 'shared'
                ? await this.tryAcquireShared()
                : await this.tryAcquireExclusive();

            if (acquired) {
                return;
            }

            await wait(retryIntervalMs);
        }

        throw new FileLockTimeoutError(this.targetFilePath, mode, timeoutMs);
    }

    /**
     * Release the lock. (Instance API — file-based)
     */
    async release(): Promise<void> {
        if (this.heldMode === 'exclusive') {
            try {
                await fs.unlink(this.exclusiveLockPath);
            } catch (err: any) {
                if (err.code !== 'ENOENT') throw err;
            }
        } else if (this.heldMode === 'shared' && this.sharedLockPath) {
            try {
                await fs.unlink(this.sharedLockPath);
            } catch (err: any) {
                if (err.code !== 'ENOENT') throw err;
            }
        }

        this.heldMode = null;
        this.sharedLockPath = null;
    }

    /**
     * Execute a function with an exclusive lock. (In-process AsyncRWLock — race-free)
     */
    static async withExclusiveLock<T>(filePath: string, fn: () => Promise<T>, timeoutMs: number = 5000): Promise<T> {
        const lock = FileLock.getProcessLock(filePath);
        await lock.acquire('exclusive', timeoutMs);
        try {
            return await fn();
        } finally {
            lock.release();
        }
    }

    /**
     * Execute a function with a shared lock. (In-process AsyncRWLock — race-free)
     */
    static async withSharedLock<T>(filePath: string, fn: () => Promise<T>, timeoutMs: number = 5000): Promise<T> {
        const lock = FileLock.getProcessLock(filePath);
        await lock.acquire('shared', timeoutMs);
        try {
            return await fn();
        } finally {
            lock.release();
        }
    }

    /**
     * Backward-compatible alias for existing call sites.
     */
    static async withLock<T>(filePath: string, fn: () => Promise<T>, timeoutMs: number = 5000): Promise<T> {
        return FileLock.withExclusiveLock(filePath, fn, timeoutMs);
    }
}

/**
 * PromptDistiller — Phase 1.3.3 Feature: Retention + Compression
 *
 * Implements a 3-tier retention policy for volatile data (prompts, traces, logs):
 * - RAW (0-7 days): Full data, instant access
 * - COMPRESSED (7-30 days): Delta-encoded + zlib, <10ms access
 * - DISTILLED (30+ days): Metadata only (~200 bytes), permanent
 *
 * Features:
 * - Emergency purge when disk > 90%
 * - READ-ONLY mode during disk full
 * - Reversible compression (RAW → COMPRESSED)
 * - Irreversible distillation (COMPRESSED → DISTILLED)
 */

import * as fs from 'fs/promises';
import { existsSync, statSync, readdirSync } from 'fs';
import * as path from 'path';
import { createHash } from 'crypto';
import { gzipSync, gunzipSync } from 'zlib';

export interface DistilledRecord {
    originalKey: string;
    timestamp: number;
    contentHash: string;  // SHA-256 of original content
    tokenCount: number;
    modelUsed: string;
    taskType: string;
    success: boolean;
    latencyMs: number;
    costUsd: number;
}

export interface PromptRecord {
    key: string;
    content: string;
    metadata: {
        tokenCount: number;
        modelUsed: string;
        taskType: string;
        success: boolean;
        latencyMs: number;
        costUsd: number;
    };
    timestamp: number;
}

export interface PromptDistillerConfig {
    dataPath: string;
    rawRetentionMs?: number;        // 0-7 days default
    compressedRetentionMs?: number; // 7-30 days default
    diskCheckIntervalMs?: number;   // 5 minutes default
    diskThresholdPercent?: number;  // 90% default
    emergencyPurgeEnabled?: boolean; // true default
    autoClassifyOnInit?: boolean;    // true default - classify existing data on initialize
    maxDiskUsageMB?: number;         // 500 default - fallback limit for own directories
}

export type StorageTier = 'raw' | 'compressed' | 'distilled';

export interface TierStats {
    tier: StorageTier;
    recordCount: number;
    sizeBytes: number;
    oldestTimestamp: number;
    newestTimestamp: number;
}

export interface PurgeResult {
    purged: boolean;
    reason?: string;
    bytesFreed: number;
    recordsRemoved: number;
    recordsCompressed: number;
    recordsDistilled: number;
    durationMs: number;
}

const RAW_RETENTION_MS = 7 * 24 * 60 * 60 * 1000;      // 7 days
const COMPRESSED_RETENTION_MS = 30 * 24 * 60 * 60 * 1000; // 30 days
const DISK_CHECK_INTERVAL_MS = 5 * 60 * 1000;          // 5 minutes
const DISK_THRESHOLD_PERCENT = 90;

export class PromptDistiller {
    private readonly rawDir: string;
    private readonly compressedDir: string;
    private readonly distilledDir: string;
    private readonly rawRetentionMs: number;
    private readonly compressedRetentionMs: number;
    private readonly diskCheckIntervalMs: number;
    private readonly diskThresholdPercent: number;
    private readonly emergencyPurgeEnabled: boolean;
    private readonly autoClassifyOnInit: boolean;
    private readonly maxDiskUsageMB: number;
    private isReadOnly = false;
    private diskCheckTimer: NodeJS.Timeout | null = null;
    private lastDiskCheck = 0;

    constructor(config: PromptDistillerConfig) {
        this.rawDir = path.join(config.dataPath, 'distiller-raw');
        this.compressedDir = path.join(config.dataPath, 'distiller-compressed');
        this.distilledDir = path.join(config.dataPath, 'distiller-distilled');
        this.rawRetentionMs = config.rawRetentionMs ?? RAW_RETENTION_MS;
        this.compressedRetentionMs = config.compressedRetentionMs ?? COMPRESSED_RETENTION_MS;
        this.diskCheckIntervalMs = config.diskCheckIntervalMs ?? DISK_CHECK_INTERVAL_MS;
        this.diskThresholdPercent = config.diskThresholdPercent ?? DISK_THRESHOLD_PERCENT;
        this.emergencyPurgeEnabled = config.emergencyPurgeEnabled ?? true;
        this.autoClassifyOnInit = config.autoClassifyOnInit ?? true;
        this.maxDiskUsageMB = config.maxDiskUsageMB ?? 500;
    }

    async initialize(): Promise<void> {
        await fs.mkdir(this.rawDir, { recursive: true });
        await fs.mkdir(this.compressedDir, { recursive: true });
        await fs.mkdir(this.distilledDir, { recursive: true });

        // Classify existing data on first run (if enabled)
        if (this.autoClassifyOnInit) {
            await this.classifyExistingData();
        }

        // Start periodic disk check
        if (this.emergencyPurgeEnabled) {
            this.startDiskMonitoring();
        }
    }

    async stop(): Promise<void> {
        if (this.diskCheckTimer) {
            clearInterval(this.diskCheckTimer);
            this.diskCheckTimer = null;
        }
    }

    /**
     * Store a new prompt record in RAW tier
     */
    async store(record: PromptRecord): Promise<void> {
        if (this.isReadOnly) {
            throw new Error('PromptDistiller is in READ-ONLY mode due to disk space');
        }

        const fileName = `${record.timestamp}-${this.sanitizeKey(record.key)}.json`;
        const filePath = path.join(this.rawDir, fileName);

        try {
            await fs.writeFile(filePath, JSON.stringify(record), 'utf8');
        } catch (err: any) {
            // If disk full during write, enter READ-ONLY mode
            if (err.code === 'ENOSPC') {
                this.isReadOnly = true;
                throw new Error('Disk full: PromptDistiller entering READ-ONLY mode');
            }
            throw err;
        }
    }

    /**
     * Retrieve a record (searches all tiers)
     */
    async retrieve(key: string, timestamp?: number): Promise<PromptRecord | DistilledRecord | null> {
        // Try RAW first (fastest)
        const rawResult = await this.searchTier('raw', key, timestamp);
        if (rawResult) return rawResult;

        // Try COMPRESSED (decompress)
        const compressedResult = await this.searchTier('compressed', key, timestamp);
        if (compressedResult) return compressedResult;

        // Try DISTILLED (metadata only)
        const distilledResult = await this.searchTier('distilled', key, timestamp);
        return distilledResult;
    }

    /**
     * Get statistics for all tiers
     */
    async getStats(): Promise<TierStats[]> {
        const stats: TierStats[] = [];

        for (const tier of ['raw', 'compressed', 'distilled'] as const) {
            const tierStats = await this.getTierStats(tier);
            stats.push(tierStats);
        }

        return stats;
    }

    /**
     * Run retention policy (compress old RAW, distill old COMPRESSED)
     */
    async runRetentionPolicy(): Promise<{
        compressed: number;
        distilled: number;
        bytesFreed: number;
    }> {
        const now = Date.now();
        let compressed = 0;
        let distilled = 0;
        let bytesFreed = 0;

        // Phase 1: RAW → COMPRESSED (7+ days old)
        const rawFiles = await this.listFiles(this.rawDir);
        for (const file of rawFiles) {
            const filePath = path.join(this.rawDir, file);
            const stats = statSync(filePath);

            // Use timestamp from filename, not mtime
            const timestamp = this.extractTimestamp(file);
            const age = now - timestamp;

            if (age >= this.rawRetentionMs) {
                const beforeSize = stats.size;
                await this.compressRecord(filePath);
                compressed++;
                bytesFreed += beforeSize;
            }
        }

        // Phase 2: COMPRESSED → DISTILLED (30+ days old)
        const compressedFiles = await this.listFiles(this.compressedDir);
        for (const file of compressedFiles) {
            const filePath = path.join(this.compressedDir, file);
            const stats = statSync(filePath);

            // Use timestamp from filename, not mtime
            const timestamp = this.extractTimestamp(file);
            const age = now - timestamp;

            if (age >= this.compressedRetentionMs) {
                const beforeSize = stats.size;
                await this.distillRecord(filePath);
                distilled++;
                bytesFreed += beforeSize;
            }
        }

        return { compressed, distilled, bytesFreed };
    }

    /**
     * Emergency purge when disk > threshold
     */
    async emergencyPurge(): Promise<PurgeResult> {
        const start = Date.now();
        const diskUsage = await this.getDiskUsagePercent();

        if (diskUsage < this.diskThresholdPercent) {
            return {
                purged: false,
                reason: 'disk_usage_below_threshold',
                bytesFreed: 0,
                recordsRemoved: 0,
                recordsCompressed: 0,
                recordsDistilled: 0,
                durationMs: Date.now() - start
            };
        }

        let bytesFreed = 0;
        let recordsRemoved = 0;
        let recordsCompressed = 0;
        let recordsDistilled = 0;

        // Step 1: Compress all RAW > 3 days
        const now = Date.now();
        const rawFiles = await this.listFiles(this.rawDir);
        for (const file of rawFiles) {
            const filePath = path.join(this.rawDir, file);
            const stats = statSync(filePath);

            // Use timestamp from filename, not mtime
            const timestamp = this.extractTimestamp(file);
            const age = now - timestamp;

            if (age >= 3 * 24 * 60 * 60 * 1000) { // 3 days
                const beforeSize = stats.size;
                await this.compressRecord(filePath);
                recordsCompressed++;
                bytesFreed += beforeSize;
            }
        }

        // Check again
        const diskUsage2 = await this.getDiskUsagePercent();
        if (diskUsage2 < this.diskThresholdPercent) {
            return {
                purged: true,
                reason: 'compressed_raw_3d',
                bytesFreed,
                recordsRemoved,
                recordsCompressed,
                recordsDistilled,
                durationMs: Date.now() - start
            };
        }

        // Step 2: Distill all COMPRESSED > 15 days
        const compressedFiles = await this.listFiles(this.compressedDir);
        for (const file of compressedFiles) {
            const filePath = path.join(this.compressedDir, file);
            const stats = statSync(filePath);

            // Use timestamp from filename, not mtime
            const timestamp = this.extractTimestamp(file);
            const age = now - timestamp;

            if (age >= 15 * 24 * 60 * 60 * 1000) { // 15 days
                const beforeSize = stats.size;
                await this.distillRecord(filePath);
                recordsDistilled++;
                bytesFreed += beforeSize;
            }
        }

        // Check again
        const diskUsage3 = await this.getDiskUsagePercent();
        if (diskUsage3 < this.diskThresholdPercent) {
            return {
                purged: true,
                reason: 'distilled_compressed_15d',
                bytesFreed,
                recordsRemoved,
                recordsCompressed,
                recordsDistilled,
                durationMs: Date.now() - start
            };
        }

        // Step 3: Aggregate distilled records (weekly groups)
        const distilledFiles = await this.listFiles(this.distilledDir);
        const weekGroups = new Map<number, string[]>();

        for (const file of distilledFiles) {
            const timestamp = this.extractTimestamp(file);
            const week = Math.floor(timestamp / (7 * 24 * 60 * 60 * 1000));
            if (!weekGroups.has(week)) weekGroups.set(week, []);
            weekGroups.get(week)!.push(file);
        }

        for (const [, files] of weekGroups) {
            if (files.length > 1) {
                // Aggregate into single file
                const aggregated: DistilledRecord[] = [];
                for (const file of files) {
                    const filePath = path.join(this.distilledDir, file);
                    const content = await fs.readFile(filePath, 'utf8');
                    const record = JSON.parse(content) as DistilledRecord;
                    aggregated.push(record);
                    await fs.unlink(filePath);
                    recordsRemoved++;
                }

                // Write aggregated file
                const firstTimestamp = Math.min(...aggregated.map(r => r.timestamp));
                const aggFileName = `${firstTimestamp}-aggregated.json`;
                const aggFilePath = path.join(this.distilledDir, aggFileName);
                await fs.writeFile(aggFilePath, JSON.stringify(aggregated), 'utf8');
            }
        }

        return {
            purged: true,
            reason: 'full_emergency_purge',
            bytesFreed,
            recordsRemoved,
            recordsCompressed,
            recordsDistilled,
            durationMs: Date.now() - start
        };
    }

    get readOnly(): boolean {
        return this.isReadOnly;
    }

    // --- Private Methods ---

    private async compressRecord(rawFilePath: string): Promise<void> {
        try {
            const content = await fs.readFile(rawFilePath, 'utf8');

            // Delta encoding (simple: store diff from baseline if possible)
            // For now, just compress the JSON
            const compressed = gzipSync(Buffer.from(content, 'utf8'));

            // Preserve timestamp in filename
            const baseName = path.basename(rawFilePath, '.json');
            const fileName = `${baseName}.gz`;
            const compressedPath = path.join(this.compressedDir, fileName);

            await fs.writeFile(compressedPath, compressed);
            await fs.unlink(rawFilePath);
        } catch (err) {
            console.warn(`[PromptDistiller] Failed to compress ${rawFilePath}:`, err);
            // On failure, data stays in RAW tier (safe)
        }
    }

    private async distillRecord(compressedFilePath: string): Promise<void> {
        try {
            const compressed = await fs.readFile(compressedFilePath);
            const content = gunzipSync(compressed).toString('utf8');
            const record = JSON.parse(content) as PromptRecord;

            const distilled: DistilledRecord = {
                originalKey: record.key,
                timestamp: record.timestamp,
                contentHash: createHash('sha256').update(record.content).digest('hex'),
                tokenCount: record.metadata.tokenCount,
                modelUsed: record.metadata.modelUsed,
                taskType: record.metadata.taskType,
                success: record.metadata.success,
                latencyMs: record.metadata.latencyMs,
                costUsd: record.metadata.costUsd
            };

            // Preserve timestamp in filename
            const baseName = path.basename(compressedFilePath, '.gz');
            const fileName = `${baseName}.distilled.json`;
            const distilledPath = path.join(this.distilledDir, fileName);

            await fs.writeFile(distilledPath, JSON.stringify(distilled), 'utf8');
            await fs.unlink(compressedFilePath);
        } catch (err) {
            console.warn(`[PromptDistiller] Failed to distill ${compressedFilePath}:`, err);
            // On failure, data stays in COMPRESSED tier (safe)
        }
    }

    private async searchTier(
        tier: StorageTier,
        key: string,
        timestamp?: number
    ): Promise<PromptRecord | DistilledRecord | null> {
        let dir: string;
        if (tier === 'raw') {
            dir = this.rawDir;
        } else if (tier === 'compressed') {
            dir = this.compressedDir;
        } else {
            dir = this.distilledDir;
        }
        const files = await this.listFiles(dir);

        for (const file of files) {
            if (timestamp && !file.startsWith(`${timestamp}-`)) continue;
            if (!file.includes(this.sanitizeKey(key))) continue;

            const filePath = path.join(dir, file);

            try {
                if (tier === 'raw') {
                    const content = await fs.readFile(filePath, 'utf8');
                    return JSON.parse(content) as PromptRecord;
                } else if (tier === 'compressed') {
                    const compressed = await fs.readFile(filePath);
                    const content = gunzipSync(compressed).toString('utf8');
                    return JSON.parse(content) as PromptRecord;
                } else {
                    const content = await fs.readFile(filePath, 'utf8');
                    const parsed = JSON.parse(content);
                    // Could be single or array (aggregated)
                    if (Array.isArray(parsed)) {
                        return parsed.find(r => r.originalKey === key) ?? null;
                    }
                    return parsed as DistilledRecord;
                }
            } catch {
                continue;
            }
        }

        return null;
    }

    private async getTierStats(tier: StorageTier): Promise<TierStats> {
        let dir: string;
        if (tier === 'raw') {
            dir = this.rawDir;
        } else if (tier === 'compressed') {
            dir = this.compressedDir;
        } else {
            dir = this.distilledDir;
        }
        const allFiles = await this.listFiles(dir);

        // Filter files by tier type
        const files = allFiles.filter(f => {
            if (tier === 'raw') return f.endsWith('.json') && !f.includes('aggregated') && !f.includes('distilled');
            if (tier === 'compressed') return f.endsWith('.gz');
            if (tier === 'distilled') return f.endsWith('.distilled.json') || f.includes('aggregated');
            return false;
        });

        let recordCount = 0;
        let sizeBytes = 0;
        let oldestTimestamp = Infinity;
        let newestTimestamp = 0;

        for (const file of files) {
            const filePath = path.join(dir, file);
            const stats = statSync(filePath);
            sizeBytes += stats.size;

            const timestamp = this.extractTimestamp(file);
            if (timestamp < oldestTimestamp) oldestTimestamp = timestamp;
            if (timestamp > newestTimestamp) newestTimestamp = timestamp;

            // Count records (aggregated files may contain multiple)
            if (file.includes('aggregated')) {
                try {
                    const content = await fs.readFile(filePath, 'utf8');
                    const parsed = JSON.parse(content);
                    recordCount += Array.isArray(parsed) ? parsed.length : 1;
                } catch {
                    recordCount++;
                }
            } else {
                recordCount++;
            }
        }

        return {
            tier,
            recordCount,
            sizeBytes,
            oldestTimestamp: oldestTimestamp === Infinity ? 0 : oldestTimestamp,
            newestTimestamp
        };
    }

    private async listFiles(dir: string): Promise<string[]> {
        try {
            return await fs.readdir(dir);
        } catch {
            return [];
        }
    }

    private async getDiskUsagePercent(): Promise<number> {
        try {
            // Primary: use fs.statfs (Node 18.15+)
            const fsStats = await fs.statfs(this.rawDir);
            if (fsStats.blocks > 0) {
                return (1 - fsStats.bfree / fsStats.blocks) * 100;
            }
        } catch {
            // statfs not available or failed — fall through to fallback
        }

        try {
            // Fallback: sum own directory sizes vs maxDiskUsageMB
            const totalBytes = this.sumDirSizeSync(this.rawDir)
                + this.sumDirSizeSync(this.compressedDir)
                + this.sumDirSizeSync(this.distilledDir);
            const limitBytes = this.maxDiskUsageMB * 1024 * 1024;
            if (limitBytes <= 0) return 0;
            return (totalBytes / limitBytes) * 100;
        } catch {
            return 0;
        }
    }

    private sumDirSizeSync(dir: string): number {
        if (!existsSync(dir)) return 0;
        let total = 0;
        for (const file of readdirSync(dir)) {
            try {
                total += statSync(path.join(dir, file)).size;
            } catch { /* skip unreadable files */ }
        }
        return total;
    }

    private sanitizeKey(key: string): string {
        return key.replace(/[^a-zA-Z0-9_-]/g, '_');
    }

    private extractTimestamp(fileName: string): number {
        const match = /^(\d+)-/.exec(fileName);
        return match ? parseInt(match[1]!, 10) : 0;
    }

    private async classifyExistingData(): Promise<void> {
        // On first run, classify any existing files into correct tiers
        const now = Date.now();

        // Check RAW for old files
        const rawFiles = await this.listFiles(this.rawDir);
        for (const file of rawFiles) {
            const filePath = path.join(this.rawDir, file);

            // Use timestamp from filename, not mtime
            const timestamp = this.extractTimestamp(file);
            const age = now - timestamp;

            if (age >= this.rawRetentionMs && age < this.compressedRetentionMs) {
                await this.compressRecord(filePath);
            } else if (age >= this.compressedRetentionMs) {
                // Direct to distilled
                await this.compressRecord(filePath);
                const compressedPath = path.join(this.compressedDir, file.replace('.json', '.gz'));
                if (existsSync(compressedPath)) {
                    await this.distillRecord(compressedPath);
                }
            }
        }

        // Check COMPRESSED for old files
        const compressedFiles = await this.listFiles(this.compressedDir);
        for (const file of compressedFiles) {
            const filePath = path.join(this.compressedDir, file);

            // Use timestamp from filename, not mtime
            const timestamp = this.extractTimestamp(file);
            const age = now - timestamp;

            if (age >= this.compressedRetentionMs) {
                await this.distillRecord(filePath);
            }
        }
    }

    private startDiskMonitoring(): void {
        this.diskCheckTimer = setInterval(async () => {
            const now = Date.now();
            if (now - this.lastDiskCheck < this.diskCheckIntervalMs) return;

            this.lastDiskCheck = now;
            const diskUsage = await this.getDiskUsagePercent();

            if (diskUsage >= this.diskThresholdPercent) {
                console.warn(`[PromptDistiller] Disk usage at ${diskUsage}% - triggering emergency purge`);
                const result = await this.emergencyPurge();
                console.log(`[PromptDistiller] Emergency purge completed: ${JSON.stringify(result)}`);

                // If still full after purge, enter READ-ONLY
                const postPurgeDiskUsage = await this.getDiskUsagePercent();
                if (postPurgeDiskUsage >= this.diskThresholdPercent) {
                    this.isReadOnly = true;
                    console.error('[PromptDistiller] READ-ONLY mode: disk still full after emergency purge');
                }
            } else if (this.isReadOnly && diskUsage < this.diskThresholdPercent - 10) {
                // Exit READ-ONLY when disk usage drops below threshold - 10%
                this.isReadOnly = false;
                console.log('[PromptDistiller] Exiting READ-ONLY mode: disk space recovered');
            }
        }, this.diskCheckIntervalMs);
    }
}

/**
 * ResilienceShell — Phase 6: Circuit Breaker + Retry + Backpressure
 *
 * Protects daemon ingest layer with circuit breaker, retry with jitter,
 * and backpressure control. Transparente para callers via error metadata.
 */

export type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';

export interface ResilienceConfig {
    circuitBreaker?: {
        failureThreshold?: number;     // default: 5
        windowMs?: number;             // default: 60000
        halfOpenAfterMs?: number;      // default: 30000
        halfOpenMaxProbes?: number;    // default: 3
    };
    backpressure?: {
        highWaterMark?: number;        // default: 1000
        lowWaterMark?: number;         // default: 200
    };
    retry?: {
        maxAttempts?: number;          // default: 3
        baseDelayMs?: number;          // default: 100
        maxDelayMs?: number;           // default: 5000
        jitterFactor?: number;         // default: 0.3
    };
    timeout?: {
        readMs?: number;               // default: 2000
        writeMs?: number;              // default: 5000
        scanMs?: number;               // default: 10000
    };
}

export interface ResilienceMetadata {
    attempts: number;
    lastError?: string;
    circuitState: CircuitState;
    queueDepth: number;
}

export class GICSUnavailable extends Error {
    metadata: ResilienceMetadata;
    constructor(message: string, metadata: ResilienceMetadata) {
        super(message);
        this.name = 'GICSUnavailable';
        this.metadata = metadata;
    }
}

export class GICSTimeout extends Error {
    metadata: ResilienceMetadata;
    constructor(message: string, metadata: ResilienceMetadata) {
        super(message);
        this.name = 'GICSTimeout';
        this.metadata = metadata;
    }
}

export class GICSCircuitOpen extends Error {
    metadata: ResilienceMetadata;
    constructor(message: string, metadata: ResilienceMetadata) {
        super(message);
        this.name = 'GICSCircuitOpen';
        this.metadata = metadata;
    }
}

export class ResilienceShell {
    private circuitState: CircuitState = 'CLOSED';
    private readonly failureThreshold: number;
    private readonly windowMs: number;
    private readonly halfOpenAfterMs: number;
    private readonly halfOpenMaxProbes: number;
    private readonly highWaterMark: number;
    private readonly lowWaterMark: number;
    private readonly retryMaxAttempts: number;
    private readonly retryBaseDelayMs: number;
    private readonly retryMaxDelayMs: number;
    private readonly jitterFactor: number;
    private readonly timeoutRead: number;
    private readonly timeoutWrite: number;
    private readonly timeoutScan: number;

    private failures: number[] = [];
    private circuitOpenedAt = 0;
    private halfOpenProbes = 0;
    private pendingOps = 0;

    constructor(config: ResilienceConfig = {}) {
        this.failureThreshold = config.circuitBreaker?.failureThreshold ?? 5;
        this.windowMs = config.circuitBreaker?.windowMs ?? 60_000;
        this.halfOpenAfterMs = config.circuitBreaker?.halfOpenAfterMs ?? 30_000;
        this.halfOpenMaxProbes = config.circuitBreaker?.halfOpenMaxProbes ?? 3;
        this.highWaterMark = config.backpressure?.highWaterMark ?? 1000;
        this.lowWaterMark = config.backpressure?.lowWaterMark ?? 200;
        this.retryMaxAttempts = config.retry?.maxAttempts ?? 3;
        this.retryBaseDelayMs = config.retry?.baseDelayMs ?? 100;
        this.retryMaxDelayMs = config.retry?.maxDelayMs ?? 5000;
        this.jitterFactor = config.retry?.jitterFactor ?? 0.3;
        this.timeoutRead = config.timeout?.readMs ?? 2000;
        this.timeoutWrite = config.timeout?.writeMs ?? 5000;
        this.timeoutScan = config.timeout?.scanMs ?? 10_000;
    }

    getCircuitState(): CircuitState {
        this.updateCircuitState();
        return this.circuitState;
    }

    getPendingOps(): number {
        return this.pendingOps;
    }

    async executeRead<T>(operation: () => Promise<T>): Promise<T> {
        return this.execute(operation, 'read', this.timeoutRead);
    }

    async executeWrite<T>(operation: () => Promise<T>): Promise<T> {
        return this.execute(operation, 'write', this.timeoutWrite);
    }

    async executeScan<T>(operation: () => Promise<T>): Promise<T> {
        return this.execute(operation, 'scan', this.timeoutScan);
    }

    private async execute<T>(
        operation: () => Promise<T>,
        type: 'read' | 'write' | 'scan',
        timeoutMs: number
    ): Promise<T> {
        this.updateCircuitState();

        // Backpressure check
        if (this.pendingOps >= this.highWaterMark) {
            throw new GICSUnavailable(
                `Backpressure: queue at highWaterMark (${this.highWaterMark})`,
                this.getMetadata(0, 'Backpressure limit reached')
            );
        }

        // Circuit breaker check
        if (this.circuitState === 'OPEN') {
            throw new GICSCircuitOpen(
                'Circuit breaker is OPEN',
                this.getMetadata(0, 'Circuit OPEN')
            );
        }

        this.pendingOps++;
        let attempts = 0;
        let lastError: Error | null = null;

        try {
            while (attempts < this.retryMaxAttempts) {
                attempts++;

                try {
                    const result = await this.withTimeout(operation(), timeoutMs);
                    this.recordSuccess();
                    return result;
                } catch (err: any) {
                    lastError = err;
                    if (err.name === 'TimeoutError') {
                        this.recordFailure();
                        // Check si circuit se abrió tras el failure
                        this.updateCircuitState();
                        if (this.getCircuitState() === 'OPEN' && attempts < this.retryMaxAttempts) {
                            break; // No más retries si circuit abrió
                        }
                        if (attempts < this.retryMaxAttempts) {
                            await this.delay(attempts);
                        }
                    } else {
                        this.recordFailure();
                        throw err; // No retry en errores no-timeout
                    }
                }
            }

            // Todos los intentos fallaron
            throw new GICSTimeout(
                `Operation timed out after ${attempts} attempts`,
                this.getMetadata(attempts, lastError?.message)
            );
        } finally {
            this.pendingOps--;
        }
    }

    private async withTimeout<T>(promise: Promise<T>, ms: number): Promise<T> {
        return Promise.race([
            promise,
            new Promise<T>((_, reject) =>
                setTimeout(() => {
                    const err = new Error('Operation timed out');
                    err.name = 'TimeoutError';
                    reject(err);
                }, ms)
            ),
        ]);
    }

    private async delay(attempt: number): Promise<void> {
        const baseDelay = Math.min(
            this.retryBaseDelayMs * Math.pow(2, attempt - 1),
            this.retryMaxDelayMs
        );
        // eslint-disable-next-line sonarjs/pseudo-random
        const jitter = baseDelay * this.jitterFactor * (Math.random() - 0.5);
        const delay = Math.max(0, baseDelay + jitter);
        await new Promise(r => setTimeout(r, delay));
    }

    private recordSuccess(): void {
        if (this.circuitState === 'HALF_OPEN') {
            this.halfOpenProbes++;
            if (this.halfOpenProbes >= this.halfOpenMaxProbes) {
                this.circuitState = 'CLOSED';
                this.failures = [];
                this.halfOpenProbes = 0;
            }
        }
    }

    private recordFailure(): void {
        const now = Date.now();
        this.failures.push(now);
        this.pruneFailures(now);

        if (this.circuitState === 'HALF_OPEN') {
            this.circuitState = 'OPEN';
            this.circuitOpenedAt = now;
            this.halfOpenProbes = 0;
        } else if (this.failures.length >= this.failureThreshold) {
            this.circuitState = 'OPEN';
            this.circuitOpenedAt = now;
        }
    }

    private updateCircuitState(): void {
        const now = Date.now();
        this.pruneFailures(now);

        if (this.circuitState === 'OPEN') {
            if (now - this.circuitOpenedAt >= this.halfOpenAfterMs) {
                this.circuitState = 'HALF_OPEN';
                this.halfOpenProbes = 0;
            }
        } else if (this.circuitState === 'CLOSED') {
            if (this.failures.length >= this.failureThreshold) {
                this.circuitState = 'OPEN';
                this.circuitOpenedAt = now;
            }
        }
    }

    private pruneFailures(now: number): void {
        this.failures = this.failures.filter(t => now - t < this.windowMs);
    }

    private getMetadata(attempts: number, lastError?: string): ResilienceMetadata {
        return {
            attempts,
            lastError,
            circuitState: this.circuitState,
            queueDepth: this.pendingOps,
        };
    }
}

import * as net from 'node:net';
import * as fs from 'node:fs/promises';
import { existsSync, writeFileSync, readFileSync, mkdirSync } from 'node:fs';
import * as path from 'node:path';
import { randomBytes } from 'node:crypto';
import { MemTable } from './memtable.js';
import { createWALProvider, Operation, type WALFsyncMode, type WALProvider, type WALType } from './wal.js';
import { FileLock } from './file-lock.js';
import { GICSv2Encoder } from '../gics/encode.js';
import { GICSv2Decoder } from '../gics/decode.js';
import type { GenericSnapshot, SchemaProfile } from '../gics-types.js';
import { GICSSupervisor } from './supervisor.js';
import { ResilienceShell, GICSCircuitOpen, GICSTimeout, GICSUnavailable, type ResilienceConfig } from './resilience.js';
import { createBuiltinModuleSet, type BuiltinModuleSet } from './builtin-modules.js';
import type { GICSModuleRuntimeConfig } from './config.js';
import type { InferenceRequest, ModuleContext } from './module-registry.js';
import { StateIndex, type StateIndexEntry, type StateIndexTier, type StateIndexScanOptions } from './state-index.js';
import { isHiddenSystemKey, isSystemKey } from './system-keys.js';

export interface GICSDaemonConfig {
    socketPath: string;
    dataPath: string;
    tokenPath: string;
    walType?: WALType;
    walFsyncMode?: WALFsyncMode;
    walFsyncOnCommit?: boolean;
    walCheckpointEveryOps?: number;
    walCheckpointEveryMs?: number;
    walMaxSizeMB?: number;
    maxMemSizeBytes?: number;
    maxDirtyCount?: number;
    fileLockTimeoutMs?: number;
    warmRetentionMs?: number;
    coldRetentionMs?: number;
    coldEncryption?: boolean;
    coldPasswordEnvVar?: string;
    resilience?: ResilienceConfig;
    modules?: Record<string, GICSModuleRuntimeConfig>;
    defaultProfileScope?: string;
    configPath?: string;
}

interface SegmentDescriptor {
    filePath: string;
    tier: 'warm' | 'cold';
    system: boolean;
}

export class GICSDaemon {
    private static readonly LEGACY_INSIGHT_SEGMENT_PREFIX = 'insight-';
    private static readonly SYSTEM_SEGMENT_PREFIX = 'insight-';
    private static readonly PRESENCE_PREFIX = '__gics_p__';
    private static readonly STATE_INDEX_FILE = 'state-index.json';
    private static readonly WRITE_OPS = new Set(['put', 'delete', 'flush', 'compact', 'rotate']);
    private static readonly READ_OPS = new Set([
        'get', 'getInsight', 'getInsights', 'getAccuracy', 'getCorrelations',
        'getClusters', 'getLeadingIndicators', 'getSeasonalPatterns', 'getForecast',
        'getAnomalies', 'getRecommendations', 'verify', 'verifyAudit', 'exportAudit',
        'infer', 'getProfile', 'getInferenceRuntime'
    ]);
    private static readonly SCAN_OPS = new Set(['scan']);
    private static readonly CONTROL_OPS = new Set([
        'ping', 'getStatus', 'getHealth', 'resetDegraded',
        'subscribe', 'unsubscribe', 'reportOutcome', 'recordOutcome', 'flushInference',
    ]);

    private readonly server: net.Server;
    private readonly memTable: MemTable;
    private readonly wal: WALProvider;
    private readonly config: GICSDaemonConfig;
    private readonly token: string;
    private recoveredEntries = 0;
    private readonly walType: WALType;
    private readonly walFsyncMode: WALFsyncMode;
    private readonly walFsyncOnCommit: boolean;
    private readonly walCheckpointEveryOps: number;
    private readonly walCheckpointEveryMs: number;
    private readonly walMaxSizeMB: number;
    private readonly fileLockTimeoutMs: number;
    private readonly storageLockTarget: string;
    private readonly warmDirPath: string;
    private readonly coldDirPath: string;
    private readonly stateIndexPath: string;
    private readonly warmRetentionMs: number;
    private readonly coldRetentionMs: number;
    private readonly coldEncryption: boolean;
    private readonly coldPasswordEnvVar: string;
    private readonly stateIndex: StateIndex;
    private readonly supervisor = new GICSSupervisor();
    private readonly resilience: ResilienceShell;
    private readonly subscriptions = new Map<string, { socket: net.Socket; events: string[] }>();
    private readonly segmentCatalog = new Map<string, SegmentDescriptor>();
    private readonly modules: BuiltinModuleSet;
    private readonly moduleContext: ModuleContext;

    constructor(config: GICSDaemonConfig) {
        this.config = config;
        this.memTable = new MemTable({
            maxMemTableBytes: config.maxMemSizeBytes,
            maxDirtyRecords: config.maxDirtyCount,
        });
        this.walType = config.walType ?? 'binary';
        this.walFsyncMode = config.walFsyncMode ?? 'best_effort';
        this.walFsyncOnCommit = config.walFsyncOnCommit ?? true;
        this.walCheckpointEveryOps = config.walCheckpointEveryOps ?? 500;
        this.walCheckpointEveryMs = config.walCheckpointEveryMs ?? 30_000;
        this.walMaxSizeMB = config.walMaxSizeMB ?? 50;
        this.fileLockTimeoutMs = config.fileLockTimeoutMs ?? 5000;
        this.storageLockTarget = path.join(config.dataPath, 'segments.lock');
        this.warmDirPath = path.join(config.dataPath, 'warm');
        this.coldDirPath = path.join(config.dataPath, 'cold');
        this.stateIndexPath = path.join(config.dataPath, GICSDaemon.STATE_INDEX_FILE);
        this.warmRetentionMs = config.warmRetentionMs ?? (30 * 24 * 60 * 60 * 1000);
        this.coldRetentionMs = config.coldRetentionMs ?? (365 * 24 * 60 * 60 * 1000);
        this.coldEncryption = config.coldEncryption ?? false;
        this.coldPasswordEnvVar = config.coldPasswordEnvVar ?? 'GICS_COLD_KEY';
        this.stateIndex = new StateIndex(this.stateIndexPath);
        this.resilience = new ResilienceShell(config.resilience);

        const walFileName = this.walType === 'jsonl' ? 'gics.wal.jsonl' : 'gics.wal';
        const walPath = path.join(config.dataPath, walFileName);
        if (!existsSync(config.dataPath)) {
            mkdirSync(config.dataPath, { recursive: true });
            writeFileSync(walPath, '');
        }
        this.wal = createWALProvider(this.walType, walPath, {
            fsyncMode: this.walFsyncMode,
            fsyncOnCommit: this.walFsyncOnCommit,
            checkpointEveryOps: this.walCheckpointEveryOps,
            checkpointEveryMs: this.walCheckpointEveryMs,
            maxWalSizeMB: this.walMaxSizeMB,
        });

        const promptEnabled = this.resolveModuleEnabled('prompt-distiller', process.env.GICS_DISTILLER_ENABLED === 'true');
        const inferenceEnabled = this.resolveModuleEnabled('inference-engine', false);
        this.modules = createBuiltinModuleSet({
            dataPath: config.dataPath,
            enablePromptDistiller: promptEnabled,
            enableInferenceEngine: inferenceEnabled,
            defaultScope: config.defaultProfileScope ?? 'host:default',
            moduleConfigs: config.modules,
        });
        this.applyModuleOverrides();

        this.moduleContext = {
            emitEvent: (type, data) => this.emitEvent(type, data),
            upsertSystemRecord: async (key, fields) => {
                await this.upsertSystemRecord(key, fields);
            },
            now: () => Date.now(),
            getStateSnapshot: () => this.stateIndex.snapshotEntries(),
        };

        this.token = this.ensureToken();
        this.server = net.createServer((socket) => this.handleConnection(socket));
    }

    private resolveModuleEnabled(moduleId: string, defaultValue: boolean): boolean {
        const override = this.config.modules?.[moduleId]?.enabled;
        return override ?? defaultValue;
    }

    private applyModuleOverrides(): void {
        for (const module of this.modules.registry.list()) {
            const override = this.config.modules?.[module.manifest.id];
            if (override?.enabled !== undefined) {
                module.enabled = override.enabled;
            }
        }
    }

    private ensureToken(): string {
        if (existsSync(this.config.tokenPath)) {
            return readFileSync(this.config.tokenPath, 'utf8').trim();
        }
        const newToken = randomBytes(16).toString('hex');
        writeFileSync(this.config.tokenPath, newToken, { mode: 0o600 });
        console.log(`[GICS] Generated new security token at ${this.config.tokenPath}`);
        return newToken;
    }

    async start(): Promise<void> {
        await FileLock.withSharedLock(this.storageLockTarget, async () => {
            await this.loadOrRebuildStateIndex();
        }, this.fileLockTimeoutMs);

        await this.modules.registry.initAll(this.moduleContext);
        await this.modules.registry.restoreAll(this.moduleContext);

        console.log('[GICS] Replaying WAL...');
        this.recoveredEntries = 0;
        await this.wal.replay((op, key, payload) => {
            const timestamp = Date.now();
            if (op === Operation.PUT) {
                this.memTable.put(key, payload);
                this.stateIndex.recordPut(key, payload, { tier: 'hot', segmentRef: null, timestamp });
                this.recoveredEntries++;
            } else if (op === Operation.DELETE) {
                this.memTable.delete(key);
                this.stateIndex.applyWALDelete(key, timestamp);
                this.recoveredEntries++;
            }
        });
        this.memTable.resetDirty();
        console.log(`[GICS] WAL replayed. ${this.memTable.count} records loaded (${this.recoveredEntries} entries replayed).`);

        await this.replayHotStateIntoModules();

        this.supervisor.registerHealthChecks({
            checkMemTable: () => {
                try { return this.memTable.count >= 0; } catch { return false; }
            },
            checkWAL: () => {
                try { return this.wal != null; } catch { return false; }
            },
            restartSubsystem: async () => {
                try {
                    return this.memTable.count >= 0;
                } catch {
                    return false;
                }
            },
        });
        this.supervisor.start();

        if (process.platform !== 'win32' && existsSync(this.config.socketPath)) {
            await fs.unlink(this.config.socketPath);
        }

        return new Promise((resolve) => {
            this.server.listen(this.config.socketPath, () => {
                console.log(`[GICS] Daemon listening on ${this.config.socketPath}`);
                resolve();
            });
        });
    }

    async stop(): Promise<void> {
        this.supervisor.stop();
        await this.stateIndex.save();
        await this.modules.registry.stopAll();
        return new Promise((resolve) => {
            this.server.close(() => {
                console.log('[GICS] Daemon stopped.');
                this.wal.close().then(resolve);
            });
        });
    }

    private async replayHotStateIntoModules(): Promise<void> {
        const records = this.memTable.scan().sort((a, b) => a.updated - b.updated);
        for (const record of records) {
            if (isHiddenSystemKey(record.key)) continue;
            await this.modules.registry.onWrite({
                key: record.key,
                fields: { ...record.fields },
                timestamp: record.updated,
            }, this.moduleContext);
        }
    }
    private handleConnection(socket: net.Socket): void {
        let buffer = '';

        socket.on('close', () => {
            for (const [subId, sub] of this.subscriptions) {
                if (sub.socket === socket) this.subscriptions.delete(subId);
            }
        });

        socket.on('data', async (data) => {
            buffer += data.toString();
            const lines = buffer.split('\n');
            buffer = lines.pop() || '';

            for (const line of lines) {
                const trimmed = line.trim();
                if (!trimmed) continue;

                let request: any;
                try {
                    request = JSON.parse(trimmed);
                } catch {
                    socket.write(JSON.stringify({
                        jsonrpc: '2.0',
                        id: null,
                        error: { code: -32700, message: 'Parse error' },
                    }) + '\n');
                    continue;
                }

                try {
                    const response = await this.handleRequest(request, socket);
                    socket.write(JSON.stringify(response) + '\n');
                } catch (e: any) {
                    socket.write(JSON.stringify({
                        jsonrpc: '2.0',
                        id: request.id ?? null,
                        error: { code: -32603, message: e?.message ?? 'Internal error' },
                    }) + '\n');
                }
            }
        });
    }

    private emitEvent(type: string, data: unknown): void {
        for (const [subId, sub] of this.subscriptions) {
            if (!sub.events.includes(type)) continue;
            if (sub.socket.destroyed) {
                this.subscriptions.delete(subId);
                continue;
            }
            const event = JSON.stringify({
                jsonrpc: '2.0',
                method: 'event',
                params: { subscriptionId: subId, type, data },
            });
            sub.socket.write(event + '\n');
        }
    }

    private isSystemSegmentFile(name: string): boolean {
        return name.startsWith(GICSDaemon.SYSTEM_SEGMENT_PREFIX) || name.startsWith(GICSDaemon.LEGACY_INSIGHT_SEGMENT_PREFIX);
    }

    private async countSegmentFiles(): Promise<number> {
        return FileLock.withSharedLock(this.storageLockTarget, async () => {
            if (!existsSync(this.warmDirPath)) return 0;
            const files = await fs.readdir(this.warmDirPath);
            return files.filter((name) => name.endsWith('.gics') && !this.isSystemSegmentFile(name)).length;
        }, this.fileLockTimeoutMs);
    }

    private async countColdSegmentFiles(): Promise<number> {
        return FileLock.withSharedLock(this.storageLockTarget, async () => {
            if (!existsSync(this.coldDirPath)) return 0;
            const files = await fs.readdir(this.coldDirPath);
            return files.filter((name) => name.endsWith('.gics') && !this.isSystemSegmentFile(name)).length;
        }, this.fileLockTimeoutMs);
    }

    private async loadOrRebuildStateIndex(): Promise<void> {
        await fs.mkdir(this.warmDirPath, { recursive: true });
        await fs.mkdir(this.coldDirPath, { recursive: true });

        let loadedFromDisk = false;
        try {
            await this.stateIndex.load();
            loadedFromDisk = true;
        } catch (err: any) {
            console.warn(`[GICS] StateIndex load failed, rebuilding from segments: ${err.message}`);
            this.stateIndex.clear();
        }

        await this.rebuildSegmentCatalog();
        if (!loadedFromDisk || !this.validateStateIndexAgainstSegments()) {
            await this.rebuildStateIndexFromSegments();
            await this.stateIndex.save();
        }
    }

    private validateStateIndexAgainstSegments(): boolean {
        for (const entry of this.stateIndex.snapshotEntries()) {
            if (entry.tier === 'hot') continue;
            if (!entry.segmentRef) return false;
            if (!this.segmentCatalog.has(entry.segmentRef)) return false;
        }
        return true;
    }

    private async rebuildSegmentCatalog(): Promise<void> {
        this.segmentCatalog.clear();
        const loadTier = async (dir: string, tier: 'warm' | 'cold') => {
            if (!existsSync(dir)) return;
            const names = (await fs.readdir(dir)).filter((name) => name.endsWith('.gics')).sort((a, b) => a.localeCompare(b));
            for (const name of names) {
                const filePath = path.join(dir, name);
                this.segmentCatalog.set(filePath, {
                    filePath,
                    tier,
                    system: this.isSystemSegmentFile(name),
                });
            }
        };

        await loadTier(this.warmDirPath, 'warm');
        await loadTier(this.coldDirPath, 'cold');
    }

    private async rebuildStateIndexFromSegments(): Promise<void> {
        this.stateIndex.clear();
        const segments = Array.from(this.segmentCatalog.values()).sort((a, b) => a.filePath.localeCompare(b.filePath));
        for (const segment of segments) {
            const raw = await fs.readFile(segment.filePath);
            const snapshots = await this.decodeSnapshotsWithFallback(raw, segment.tier === 'cold');
            for (const snapshot of snapshots) {
                for (const [rawKey, rawFields] of snapshot.items.entries()) {
                    const key = String(rawKey);
                    const fields = this.restoreOriginalFieldShape(rawFields);
                    this.stateIndex.recordPut(key, fields, {
                        timestamp: snapshot.timestamp,
                        tier: segment.tier,
                        segmentRef: segment.filePath,
                    });
                }
            }
        }
    }

    private async decodeSnapshotsWithFallback(raw: Buffer, coldTier: boolean): Promise<GenericSnapshot<Record<string, number | string>>[]> {
        try {
            const decoder = new GICSv2Decoder(raw);
            return await decoder.getAllGenericSnapshots();
        } catch {
            if (!coldTier) throw new Error('Failed to decode warm segment');
            const password = process.env[this.coldPasswordEnvVar] ?? '';
            if (!password) throw new Error(`Failed to decode cold segment and no ${this.coldPasswordEnvVar} provided`);
            const decoder = new GICSv2Decoder(raw, { password });
            return await decoder.getAllGenericSnapshots();
        }
    }

    private async querySnapshotsWithFallback(raw: Buffer, key: string, coldTier: boolean): Promise<GenericSnapshot<Record<string, number | string>>[]> {
        try {
            const decoder = new GICSv2Decoder(raw);
            return await decoder.queryGeneric(key);
        } catch {
            if (!coldTier) throw new Error('Failed to query warm segment');
            const password = process.env[this.coldPasswordEnvVar] ?? '';
            if (!password) throw new Error(`Failed to query cold segment and no ${this.coldPasswordEnvVar} provided`);
            const decoder = new GICSv2Decoder(raw, { password });
            return await decoder.queryGeneric(key);
        }
    }

    private async hydrateEntryFromSegment(entry: StateIndexEntry): Promise<StateIndexEntry | null> {
        if (!entry.segmentRef) return null;
        const segment = this.segmentCatalog.get(entry.segmentRef);
        if (!segment) return null;
        const raw = await fs.readFile(entry.segmentRef);
        const snapshots = await this.querySnapshotsWithFallback(raw, entry.key, segment.tier === 'cold');

        let winner: { timestamp: number; fields: Record<string, number | string> } | null = null;
        for (const snapshot of snapshots) {
            const fields = snapshot.items.get(entry.key);
            if (!fields) continue;
            if (!winner || snapshot.timestamp >= winner.timestamp) {
                winner = { timestamp: snapshot.timestamp, fields: this.restoreOriginalFieldShape(fields) };
            }
        }

        if (!winner) return null;
        this.stateIndex.recordPut(entry.key, winner.fields, {
            timestamp: winner.timestamp,
            tier: segment.tier,
            segmentRef: entry.segmentRef,
        });
        return this.stateIndex.getVisible(entry.key, true);
    }

    private restoreOriginalFieldShape(fields: Record<string, number | string>): Record<string, number | string> {
        const restored: Record<string, number | string> = {};
        const presence = new Map<string, number>();

        for (const [key, value] of Object.entries(fields)) {
            if (!key.startsWith(GICSDaemon.PRESENCE_PREFIX)) {
                restored[key] = value;
                continue;
            }
            const target = key.slice(GICSDaemon.PRESENCE_PREFIX.length);
            presence.set(target, typeof value === 'number' ? value : Number(value));
        }

        for (const [fieldName, flag] of presence.entries()) {
            if (flag === 0) delete restored[fieldName];
        }
        return restored;
    }

    private serializeRecordWithPresence(fields: Record<string, number | string>): Record<string, number | string> {
        const out: Record<string, number | string> = { ...fields };
        for (const fieldName of Object.keys(fields)) {
            out[`${GICSDaemon.PRESENCE_PREFIX}${fieldName}`] = 1;
        }
        return out;
    }

    private inferSchemaAndSnapshot(records: Array<{ key: string; fields: Record<string, number | string>; updated: number }>): {
        schema: SchemaProfile;
        snapshot: GenericSnapshot<Record<string, number | string>>;
    } {
        const serialized = records.map((record) => this.serializeRecordWithPresence(record.fields));
        const inferredSchema = this.inferSchemaFromFields(serialized);

        const items = new Map<string, Record<string, number | string>>();
        let snapshotTimestamp = Date.now();
        for (const record of records) {
            snapshotTimestamp = Math.max(snapshotTimestamp, record.updated);
            items.set(record.key, this.serializeRecordWithPresence(record.fields));
        }

        return {
            schema: inferredSchema,
            snapshot: { timestamp: snapshotTimestamp, items },
        };
    }
    private inferSchemaFromFields(allFields: Array<Record<string, number | string>>): SchemaProfile {
        const fieldNames = new Set<string>();
        for (const fields of allFields) {
            for (const fieldName of Object.keys(fields)) {
                fieldNames.add(fieldName);
            }
        }

        const fields: SchemaProfile['fields'] = [];
        const sortedFieldNames = Array.from(fieldNames).sort((a, b) => a.localeCompare(b));
        for (const fieldName of sortedFieldNames) {
            const values = allFields
                .map((entry) => entry[fieldName])
                .filter((value): value is number | string => value != null);

            const isNumeric = values.every((value) => typeof value === 'number');
            if (isNumeric) {
                fields.push({
                    name: fieldName,
                    type: 'numeric',
                    codecStrategy: 'value',
                });
                continue;
            }

            const enumMap: Record<string, number> = { '__MISSING__': 0 };
            let idx = 1;
            const categoricalValues = Array.from(new Set(values.filter((value): value is string => typeof value === 'string'))).sort((a, b) => a.localeCompare(b));
            for (const value of categoricalValues) {
                if (!(value in enumMap)) {
                    enumMap[value] = idx++;
                }
            }

            fields.push({
                name: fieldName,
                type: 'categorical',
                codecStrategy: 'structural',
                enumMap,
            });
        }

        return {
            id: 'gics_daemon_memtable_v2',
            version: 2,
            itemIdType: 'string',
            fields,
        };
    }

    private async writeSegment(filePath: string, records: Array<{ key: string; fields: Record<string, number | string>; updated: number }>): Promise<number> {
        const { schema, snapshot } = this.inferSchemaAndSnapshot(records);
        const encoder = new GICSv2Encoder({ schema });
        await encoder.addSnapshot(snapshot);
        const packed = await encoder.finish();
        await fs.writeFile(filePath, packed);
        return packed.length;
    }

    private async flushMemTableToWarm(trigger: 'manual' | 'auto', reason: string | null = null): Promise<{
        recordsBeforeFlush: number;
        dirtyBeforeFlush: number;
        recordsFlushed: number;
        bytesWritten: number;
        segmentCreated: string | null;
        systemSegmentCreated: string | null;
        flushDurationMs: number;
        walTruncated: boolean;
        trigger: 'manual' | 'auto';
        reason: string | null;
    }> {
        const start = Date.now();
        const recordsBeforeFlush = this.memTable.count;
        const dirtyBeforeFlush = this.memTable.dirtyCount;

        if (recordsBeforeFlush === 0 || dirtyBeforeFlush === 0) {
            this.memTable.resetDirty();
            await this.wal.truncate();
            return {
                recordsBeforeFlush,
                dirtyBeforeFlush,
                recordsFlushed: 0,
                bytesWritten: 0,
                segmentCreated: null,
                systemSegmentCreated: null,
                flushDurationMs: Date.now() - start,
                walTruncated: true,
                trigger,
                reason,
            };
        }

        const dirtyRecords = this.memTable.scan().filter((record) => record.dirty);
        const userRecords = dirtyRecords.filter((record) => !isSystemKey(record.key));
        const systemRecordMap = new Map<string, { key: string; fields: Record<string, number | string>; updated: number }>();
        const now = Date.now();

        for (const record of dirtyRecords) {
            if (!isSystemKey(record.key)) continue;
            systemRecordMap.set(record.key, { key: record.key, fields: { ...record.fields }, updated: record.updated });
        }

        for (const [key, fields] of this.modules.nativeInsight.snapshotBehavioral()) {
            systemRecordMap.set(key, { key, fields, updated: now });
        }
        for (const [key, fields] of this.modules.nativeInsight.snapshotCorrelations()) {
            systemRecordMap.set(key, { key, fields, updated: now });
        }
        for (const [key, fields] of this.modules.nativeInsight.snapshotConfidence()) {
            systemRecordMap.set(key, { key, fields, updated: now });
        }

        await fs.mkdir(this.warmDirPath, { recursive: true });
        let userSegmentPath: string | null = null;
        let systemSegmentPath: string | null = null;
        let bytesWritten = 0;

        if (userRecords.length > 0) {
            userSegmentPath = path.join(this.warmDirPath, `warm-${Date.now()}-${randomBytes(4).toString('hex')}.gics`);
            bytesWritten += await this.writeSegment(userSegmentPath, userRecords.map((record) => ({
                key: record.key,
                fields: { ...record.fields },
                updated: record.updated,
            })));
            for (const record of userRecords) {
                this.stateIndex.recordPut(record.key, record.fields, {
                    timestamp: record.updated,
                    tier: 'warm',
                    segmentRef: userSegmentPath,
                });
            }
            this.segmentCatalog.set(userSegmentPath, { filePath: userSegmentPath, tier: 'warm', system: false });
        }

        const systemRecords = Array.from(systemRecordMap.values());
        if (systemRecords.length > 0) {
            systemSegmentPath = path.join(this.warmDirPath, `${GICSDaemon.SYSTEM_SEGMENT_PREFIX}${Date.now()}-${randomBytes(4).toString('hex')}.gics`);
            bytesWritten += await this.writeSegment(systemSegmentPath, systemRecords);
            for (const record of systemRecords) {
                this.stateIndex.recordPut(record.key, record.fields, {
                    timestamp: record.updated,
                    tier: 'warm',
                    segmentRef: systemSegmentPath,
                });
            }
            this.segmentCatalog.set(systemSegmentPath, { filePath: systemSegmentPath, tier: 'warm', system: true });
        }

        this.memTable.clear();
        await this.wal.truncate();
        await this.stateIndex.save();

        await this.modules.registry.onFlush({
            trigger,
            recordsFlushed: dirtyRecords.length,
            bytesWritten,
            segmentCreated: userSegmentPath,
        }, this.moduleContext);

        return {
            recordsBeforeFlush,
            dirtyBeforeFlush,
            recordsFlushed: dirtyRecords.length,
            bytesWritten,
            segmentCreated: userSegmentPath,
            systemSegmentCreated: systemSegmentPath,
            flushDurationMs: Date.now() - start,
            walTruncated: true,
            trigger,
            reason,
        };
    }

    private async compactWarmSegments(): Promise<{
        compacted: boolean;
        reason?: string;
        segmentsMerged: number;
        recordsDeduplicated: number;
        bytesBefore: number;
        bytesAfter: number;
        spaceReclaimedBytes: number;
        outputSegment: string | null;
    }> {
        await fs.mkdir(this.warmDirPath, { recursive: true });
        const warmFiles = (await fs.readdir(this.warmDirPath))
            .filter((name) => name.endsWith('.gics') && !this.isSystemSegmentFile(name))
            .sort((a, b) => a.localeCompare(b));

        if (warmFiles.length < 2) {
            return {
                compacted: false,
                reason: 'not_enough_segments',
                segmentsMerged: 0,
                recordsDeduplicated: 0,
                bytesBefore: 0,
                bytesAfter: 0,
                spaceReclaimedBytes: 0,
                outputSegment: null,
            };
        }

        const warmState = this.stateIndex.snapshotEntries()
            .filter((entry) => entry.tier === 'warm' && !entry.deleted && entry.fields && !isSystemKey(entry.key));

        const mergedRecords = warmState.map((entry) => ({
            key: entry.key,
            fields: { ...entry.fields! },
            updated: entry.timestamp,
        }));

        let bytesBefore = 0;
        const oldSegmentRefs: string[] = [];
        for (const fileName of warmFiles) {
            const filePath = path.join(this.warmDirPath, fileName);
            const stat = await fs.stat(filePath);
            bytesBefore += stat.size;
            oldSegmentRefs.push(filePath);
        }

        const outputSegment = path.join(this.warmDirPath, `compact-${Date.now()}-${randomBytes(4).toString('hex')}.gics`);
        const bytesAfter = await this.writeSegment(outputSegment, mergedRecords);

        for (const filePath of oldSegmentRefs) {
            await fs.unlink(filePath);
            this.segmentCatalog.delete(filePath);
        }
        this.segmentCatalog.set(outputSegment, { filePath: outputSegment, tier: 'warm', system: false });

        const remap = new Map<string, { tier: StateIndexTier; segmentRef: string | null }>();
        for (const oldRef of oldSegmentRefs) {
            remap.set(oldRef, { tier: 'warm', segmentRef: outputSegment });
        }
        this.stateIndex.remapSegments(remap);
        await this.stateIndex.save();

        await this.modules.registry.onCompact({ compacted: true, segmentsMerged: warmFiles.length }, this.moduleContext);
        return {
            compacted: true,
            segmentsMerged: warmFiles.length,
            recordsDeduplicated: Math.max(0, warmFiles.length - 1),
            bytesBefore,
            bytesAfter,
            spaceReclaimedBytes: Math.max(0, bytesBefore - bytesAfter),
            outputSegment,
        };
    }
    private async reencodeForColdEncryption(inputPath: string, outputPath: string, password: string): Promise<number> {
        const raw = await fs.readFile(inputPath);
        const decoder = new GICSv2Decoder(raw);
        await decoder.parseHeader();
        const schema = decoder.getSchema();
        const snapshots = await decoder.getAllGenericSnapshots();

        const encoder = new GICSv2Encoder({ schema, password });
        for (const snapshot of snapshots) {
            await encoder.addSnapshot(snapshot);
        }
        const encrypted = await encoder.finish();
        await fs.writeFile(outputPath, encrypted);
        return encrypted.length;
    }

    // eslint-disable-next-line sonarjs/cognitive-complexity
    private async rotateWarmToCold(): Promise<{
        rotated: boolean;
        filesArchived: number;
        filesDeleted: number;
        bytesArchived: number;
        archivedFiles: string[];
        deletedColdFiles: string[];
    }> {
        await fs.mkdir(this.warmDirPath, { recursive: true });
        await fs.mkdir(this.coldDirPath, { recursive: true });

        const now = Date.now();
        const warmFiles = (await fs.readdir(this.warmDirPath)).filter((name) => name.endsWith('.gics'));
        const archivedFiles: string[] = [];
        let bytesArchived = 0;

        const password = process.env[this.coldPasswordEnvVar] ?? '';
        if (this.coldEncryption && !password) {
            throw new Error(`Cold encryption enabled but env var ${this.coldPasswordEnvVar} is missing`);
        }

        const remap = new Map<string, { tier: StateIndexTier; segmentRef: string | null }>();
        for (const fileName of warmFiles) {
            const warmPath = path.join(this.warmDirPath, fileName);
            const st = await fs.stat(warmPath);
            if ((now - st.mtimeMs) < this.warmRetentionMs) continue;

            const prefix = this.isSystemSegmentFile(fileName) ? GICSDaemon.SYSTEM_SEGMENT_PREFIX : 'cold-';
            const coldName = `${prefix}${Date.now()}-${randomBytes(4).toString('hex')}.gics`;
            const coldPath = path.join(this.coldDirPath, coldName);

            if (this.coldEncryption) {
                bytesArchived += await this.reencodeForColdEncryption(warmPath, coldPath, password);
                await fs.unlink(warmPath);
            } else {
                await fs.rename(warmPath, coldPath);
                bytesArchived += st.size;
            }

            archivedFiles.push(coldPath);
            this.segmentCatalog.delete(warmPath);
            this.segmentCatalog.set(coldPath, {
                filePath: coldPath,
                tier: 'cold',
                system: this.isSystemSegmentFile(fileName),
            });
            remap.set(warmPath, { tier: 'cold', segmentRef: coldPath });
        }

        const deletedColdFiles: string[] = [];
        if (this.coldRetentionMs > 0) {
            const coldFiles = (await fs.readdir(this.coldDirPath)).filter((name) => name.endsWith('.gics'));
            for (const fileName of coldFiles) {
                const coldPath = path.join(this.coldDirPath, fileName);
                const st = await fs.stat(coldPath);
                if ((now - st.mtimeMs) <= this.coldRetentionMs) continue;
                await fs.unlink(coldPath);
                deletedColdFiles.push(coldPath);
                this.segmentCatalog.delete(coldPath);
                this.stateIndex.removeEntriesForSegment(coldPath);
            }
        }

        if (remap.size > 0) {
            this.stateIndex.remapSegments(remap);
        }
        await this.stateIndex.save();
        await this.modules.registry.onRotate({
            rotated: archivedFiles.length > 0 || deletedColdFiles.length > 0,
            filesArchived: archivedFiles.length,
        }, this.moduleContext);

        return {
            rotated: archivedFiles.length > 0 || deletedColdFiles.length > 0,
            filesArchived: archivedFiles.length,
            filesDeleted: deletedColdFiles.length,
            bytesArchived,
            archivedFiles,
            deletedColdFiles,
        };
    }

    private async upsertSystemRecord(key: string, fields: Record<string, number | string>): Promise<void> {
        await this.wal.append(Operation.PUT, key, fields);
        this.memTable.put(key, fields);
        this.stateIndex.recordPut(key, fields, {
            tier: 'hot',
            segmentRef: null,
            timestamp: Date.now(),
        });
    }

    private getTierIndexStats(): { hotKeys: number; warmKeys: number; coldKeys: number; } {
        let hotKeys = 0;
        let warmKeys = 0;
        let coldKeys = 0;
        for (const entry of this.stateIndex.snapshotEntries()) {
            if (entry.deleted || isHiddenSystemKey(entry.key)) continue;
            if (entry.tier === 'hot') hotKeys++;
            else if (entry.tier === 'warm') warmKeys++;
            else coldKeys++;
        }
        return { hotKeys, warmKeys, coldKeys };
    }

    private async handlePut(id: any, params: any): Promise<any> {
        if (this.supervisor.isDegraded()) {
            const buffered = this.supervisor.bufferWrite(params.key, params.fields);
            return { jsonrpc: '2.0', id, result: { ok: true, degraded: true, bufferedSeq: buffered.seq } };
        }

        const timestamp = Date.now();
        await this.modules.registry.beforeWrite({
            key: params.key,
            fields: { ...params.fields },
            timestamp,
        }, this.moduleContext);

        await this.wal.append(Operation.PUT, params.key, params.fields);
        this.memTable.put(params.key, params.fields);
        this.stateIndex.recordPut(params.key, params.fields, {
            tier: 'hot',
            segmentRef: null,
            timestamp,
        });
        await this.modules.registry.onWrite({
            key: params.key,
            fields: { ...params.fields },
            timestamp,
        }, this.moduleContext);

        const behavior = this.modules.nativeInsight.getInsight(params.key) ?? undefined;
        const flushDecision = this.memTable.shouldFlush();
        if (!flushDecision.shouldFlush) {
            return { jsonrpc: '2.0', id, result: { ok: true, behavior } };
        }

        const autoFlush = await FileLock.withExclusiveLock(this.storageLockTarget, async () => {
            return this.flushMemTableToWarm('auto', flushDecision.reason);
        }, this.fileLockTimeoutMs);

        return {
            jsonrpc: '2.0',
            id,
            result: {
                ok: true,
                behavior,
                autoFlushed: true,
                flush: autoFlush,
            },
        };
    }

    private async handleGet(id: any, params: any): Promise<any> {
        const key = String(params?.key ?? '');
        const includeSystem = Boolean(params?.includeSystem ?? isSystemKey(key));
        let entry = this.stateIndex.getVisible(key, includeSystem);
        if (!entry) {
            const rawEntry = this.stateIndex.getEntry(key);
            if (rawEntry && !rawEntry.fields && !rawEntry.deleted) {
                entry = await this.hydrateEntryFromSegment(rawEntry);
            }
        }
        if (!entry || entry.deleted || (!includeSystem && isHiddenSystemKey(entry.key)) || !entry.fields) {
            return { jsonrpc: '2.0', id, result: null };
        }

        if (entry.tier !== 'hot' && !isHiddenSystemKey(entry.key)) {
            this.modules.nativeInsight.coldStartBootstrap(entry.key);
        }
        await this.modules.registry.onRead({ key: entry.key, timestamp: Date.now() }, this.moduleContext);
        const behavior = isHiddenSystemKey(entry.key) ? null : this.modules.nativeInsight.getInsight(entry.key);
        return {
            jsonrpc: '2.0',
            id,
            result: {
                key: entry.key,
                fields: { ...entry.fields },
                tier: entry.tier,
                behavior,
            },
        };
    }

    private async handleDelete(id: any, params: any): Promise<any> {
        const key = String(params?.key ?? '');
        const timestamp = Date.now();
        const { tombstoneKey, tombstoneFields } = this.stateIndex.recordDelete(key, {
            tier: 'hot',
            segmentRef: null,
            timestamp,
        });

        await this.modules.registry.beforeDelete({
            key,
            timestamp,
            tombstoneKey,
        }, this.moduleContext);

        await this.wal.append(Operation.DELETE, key, {});
        await this.wal.append(Operation.PUT, tombstoneKey, tombstoneFields);
        this.memTable.delete(key);
        this.memTable.put(tombstoneKey, tombstoneFields);
        await this.modules.registry.onDelete({ key, timestamp, tombstoneKey }, this.moduleContext);
        return { jsonrpc: '2.0', id, result: { ok: true, tombstoneKey } };
    }

    private async handleScan(id: any, params: any): Promise<any> {
        const options: StateIndexScanOptions = {
            tiers: params?.tiers ?? 'all',
            includeSystem: Boolean(params?.includeSystem ?? false),
            limit: params?.limit,
            cursor: params?.cursor ?? null,
            mode: params?.mode ?? 'current',
        };
        const result = this.stateIndex.scan(String(params?.prefix ?? ''), options);
        await this.modules.registry.onScan(result, this.moduleContext);
        return {
            jsonrpc: '2.0',
            id,
            result: {
                items: result.items.map((item) => ({
                    key: item.key,
                    fields: item.fields,
                    tier: item.tier,
                    timestamp: item.timestamp,
                })),
                nextCursor: result.nextCursor,
            },
        };
    }
    private async handleReportOutcome(id: any, params: any): Promise<any> {
        const insightId = String(params?.insightId ?? '');
        const result = String(params?.result ?? '');
        const domain = params?.domain ? String(params.domain) : undefined;
        const decisionId = params?.decisionId ? String(params.decisionId) : undefined;
        const timestamp = Date.now();
        const outcomeEvent = {
            insightId: insightId || undefined,
            result,
            domain,
            decisionId,
            context: params?.context,
            metrics: params?.metrics,
            timestamp,
        };

        let disabled = false;
        if (insightId) {
            const recorded = this.modules.nativeInsight.recordOutcome(insightId, result as any);
            if (!recorded?.found) {
                return { jsonrpc: '2.0', id, error: { code: -32602, message: `Insight ${insightId} not found` } };
            }
            disabled = recorded.nowDisabled;
            if (!recorded.wasDisabled && recorded.nowDisabled) {
                this.emitEvent('insight_disabled', { insightId, result });
            }
        }

        await this.dispatchOutcomeToModules(outcomeEvent);

        return {
            jsonrpc: '2.0',
            id,
            result: {
                ok: true,
                insightId: insightId || undefined,
                decisionId,
                domain,
                result,
                recordedAt: timestamp,
                disabled,
            },
        };
    }

    private async handleRecommendations(id: any, params: any): Promise<any> {
        const predictive = this.modules.nativeInsight.getSignalRecommendations(params);
        const moduleRecommendations = await this.modules.registry.getRecommendations({
            domain: params?.domain,
            subject: params?.subject,
            limit: params?.limit,
        }, this.moduleContext);
        const limit = Math.max(0, Number(params?.limit ?? 0));
        const combined = [...predictive, ...moduleRecommendations];
        return { jsonrpc: '2.0', id, result: limit > 0 ? combined.slice(0, limit) : combined };
    }

    private async handleInfer(id: any, params: any): Promise<any> {
        const request: InferenceRequest = {
            domain: String(params?.domain ?? ''),
            objective: params?.objective ? String(params.objective) : undefined,
            subject: params?.subject ? String(params.subject) : undefined,
            context: params?.context ?? {},
            candidates: Array.isArray(params?.candidates) ? params.candidates : [],
        };
        if (!request.domain) {
            return { jsonrpc: '2.0', id, error: { code: -32602, message: 'infer requires domain' } };
        }
        const decision = await this.modules.registry.infer(request, this.moduleContext);
        return { jsonrpc: '2.0', id, result: decision };
    }

    private async handleGetProfile(id: any, params: any): Promise<any> {
        const scope = String(params?.scope ?? this.config.defaultProfileScope ?? 'host:default');
        const profile = await this.modules.registry.getProfile(scope, this.moduleContext);
        return { jsonrpc: '2.0', id, result: profile };
    }

    private async handleGetInferenceRuntime(id: any): Promise<any> {
        const inferenceModule = this.modules.inferenceEngine;
        if (!inferenceModule?.enabled) {
            return { jsonrpc: '2.0', id, error: { code: -32602, message: 'Inference engine is not enabled' } };
        }
        return { jsonrpc: '2.0', id, result: await inferenceModule.snapshot?.() ?? await inferenceModule.health?.() ?? null };
    }

    private async handleFlushInference(id: any): Promise<any> {
        const inferenceModule = this.modules.inferenceEngine;
        if (!inferenceModule || !inferenceModule.enabled || typeof inferenceModule.forceFlush !== 'function') {
            return { jsonrpc: '2.0', id, error: { code: -32602, message: 'Inference engine flush is unavailable' } };
        }
        await inferenceModule.forceFlush();
        return { jsonrpc: '2.0', id, result: { ok: true } };
    }

    private async dispatchOutcomeToModules(event: {
        insightId?: string;
        result?: string;
        domain?: string;
        decisionId?: string;
        context?: unknown;
        metrics?: Record<string, number>;
        timestamp: number;
    }): Promise<void> {
        for (const module of this.modules.registry.enabled()) {
            if (module.manifest.id === 'native-insight') continue;
            await module.onOutcome?.(event, this.moduleContext);
        }
    }

    private async handleRequest(request: any, socket?: net.Socket): Promise<any> {
        const { method, params, id, token } = request;

        if (!method || typeof method !== 'string') {
            return {
                jsonrpc: '2.0',
                id: id ?? null,
                error: { code: -32600, message: 'Invalid Request' },
            };
        }

        if (token !== this.token && method !== 'ping') {
            return { jsonrpc: '2.0', id, error: { code: -32000, message: 'Unauthorized' } };
        }

        try {
            const exec = () => this.executeMethod(method, params, id, socket);
            if (GICSDaemon.CONTROL_OPS.has(method)) {
                return await exec();
            }
            if (GICSDaemon.WRITE_OPS.has(method)) {
                return await this.resilience.executeWrite(exec);
            }
            if (GICSDaemon.SCAN_OPS.has(method)) {
                return await this.resilience.executeScan(exec);
            }
            if (GICSDaemon.READ_OPS.has(method)) {
                return await this.resilience.executeRead(exec);
            }
            return await exec();
        } catch (e: any) {
            if (e instanceof GICSCircuitOpen) {
                return { jsonrpc: '2.0', id, error: { code: -32001, message: e.message, data: e.metadata } };
            }
            if (e instanceof GICSTimeout) {
                return { jsonrpc: '2.0', id, error: { code: -32002, message: e.message, data: e.metadata } };
            }
            if (e instanceof GICSUnavailable) {
                return { jsonrpc: '2.0', id, error: { code: -32003, message: e.message, data: e.metadata } };
            }
            return { jsonrpc: '2.0', id, error: { code: -32603, message: e.message } };
        }
    }

    // eslint-disable-next-line sonarjs/cognitive-complexity
    private async executeMethod(method: string, params: any, id: any, socket?: net.Socket): Promise<any> {
        try {
            // eslint-disable-next-line sonarjs/max-switch-cases
            switch (method) {
                case 'getStatus':
                    return { jsonrpc: '2.0', id, result: { ...this.supervisor.getStatus(), circuitState: this.resilience.getCircuitState(), pendingOps: this.resilience.getPendingOps() } };

                case 'resetDegraded': {
                    if (!this.supervisor.isDegraded()) {
                        return { jsonrpc: '2.0', id, error: { code: -32602, message: 'Daemon is not in DEGRADED state' } };
                    }
                    const resetOk = await this.supervisor.resetDegraded();
                    if (resetOk) {
                        const walKeys = new Set<string>();
                        this.memTable.scan('').forEach((record) => walKeys.add(record.key));
                        const flushResult = this.supervisor.flushBuffer(
                            (key) => walKeys.has(key),
                            (key, fields) => {
                                this.memTable.put(key, fields);
                                this.stateIndex.recordPut(key, fields, { tier: 'hot', segmentRef: null, timestamp: Date.now() });
                            }
                        );
                        return { jsonrpc: '2.0', id, result: { ok: true, flush: flushResult } };
                    }
                    return { jsonrpc: '2.0', id, error: { code: -32603, message: 'Failed to exit DEGRADED state' } };
                }

                case 'put':
                    return await this.handlePut(id, params);

                case 'get':
                    return await this.handleGet(id, params);

                case 'getInsight':
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getInsight(String(params?.key ?? '')) };

                case 'getInsights': {
                    const lifecycle = params?.lifecycle;
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getInsights(lifecycle ? { lifecycle } : undefined) };
                }

                case 'recordOutcome':
                case 'reportOutcome':
                    return await this.handleReportOutcome(id, params);

                case 'subscribe': {
                    const subEvents = Array.isArray(params?.events) ? params.events as string[] : [];
                    const subscriptionId = `sub_${Date.now()}_${randomBytes(3).toString('hex')}`;
                    if (socket) {
                        this.subscriptions.set(subscriptionId, { socket, events: subEvents });
                    }
                    return { jsonrpc: '2.0', id, result: { subscriptionId, events: subEvents } };
                }

                case 'unsubscribe': {
                    const unsubId = String(params?.subscriptionId ?? '');
                    const deleted = this.subscriptions.delete(unsubId);
                    return { jsonrpc: '2.0', id, result: { ok: deleted } };
                }

                case 'getAccuracy':
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getAccuracy(params?.insightType, params?.scope) };

                case 'getCorrelations':
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getCorrelations(params?.key) };

                case 'getClusters':
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getClusters() };

                case 'getLeadingIndicators':
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getLeadingIndicators(params?.key) };

                case 'getSeasonalPatterns':
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getSeasonalPatterns(params?.key) };

                case 'getForecast':
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getForecast(String(params?.key ?? ''), String(params?.field ?? ''), params?.horizon) };

                case 'getAnomalies':
                    return { jsonrpc: '2.0', id, result: this.modules.nativeInsight.getAnomalies(params?.since) };

                case 'getRecommendations':
                    return await this.handleRecommendations(id, params);

                case 'infer':
                    return await this.handleInfer(id, params);

                case 'getProfile':
                    return await this.handleGetProfile(id, params);

                case 'getInferenceRuntime':
                    return await this.handleGetInferenceRuntime(id);

                case 'flushInference':
                    return await this.handleFlushInference(id);

                case 'delete':
                    return await this.handleDelete(id, params);

                case 'scan':
                    return await this.handleScan(id, params);

                case 'verify': {
                    const tier = params?.tier as 'warm' | 'cold' | undefined;
                    return FileLock.withSharedLock(this.storageLockTarget, async () => {
                        const details: Array<{ file: string; tier: string; valid: boolean; error?: string }> = [];
                        const tiers: Array<'warm' | 'cold'> = tier ? [tier] : ['warm', 'cold'];
                        for (const currentTier of tiers) {
                            const dir = currentTier === 'warm' ? this.warmDirPath : this.coldDirPath;
                            if (!existsSync(dir)) continue;
                            const files = (await fs.readdir(dir)).filter((name) => name.endsWith('.gics'));
                            for (const fileName of files) {
                                const filePath = path.join(dir, fileName);
                                try {
                                    const raw = await fs.readFile(filePath);
                                    const decoder = currentTier === 'cold' && (process.env[this.coldPasswordEnvVar] ?? '')
                                        ? new GICSv2Decoder(raw, { password: process.env[this.coldPasswordEnvVar] })
                                        : new GICSv2Decoder(raw);
                                    const valid = await decoder.verifyIntegrityOnly();
                                    details.push({ file: fileName, tier: currentTier, valid });
                                } catch (e: any) {
                                    details.push({ file: fileName, tier: currentTier, valid: false, error: e.message });
                                }
                            }
                        }
                        return { jsonrpc: '2.0', id, result: { valid: details.every((item) => item.valid), details } };
                    }, this.fileLockTimeoutMs);
                }

                case 'flush':
                    return FileLock.withExclusiveLock(this.storageLockTarget, async () => {
                        const flushResult = await this.flushMemTableToWarm('manual');
                        return { jsonrpc: '2.0', id, result: { ok: true, ...flushResult } };
                    }, this.fileLockTimeoutMs);

                case 'compact':
                    return FileLock.withExclusiveLock(this.storageLockTarget, async () => {
                        const compaction = await this.compactWarmSegments();
                        return { jsonrpc: '2.0', id, result: { ok: true, ...compaction } };
                    }, this.fileLockTimeoutMs);

                case 'rotate':
                    return FileLock.withExclusiveLock(this.storageLockTarget, async () => {
                        const rotation = await this.rotateWarmToCold();
                        return { jsonrpc: '2.0', id, result: { ok: true, ...rotation } };
                    }, this.fileLockTimeoutMs);

                case 'verifyAudit': {
                    const auditResult = await this.modules.auditChain.verify();
                    return { jsonrpc: '2.0', id, result: auditResult };
                }

                case 'exportAudit': {
                    const auditLines = await this.modules.auditChain.export();
                    return { jsonrpc: '2.0', id, result: { entries: auditLines } };
                }

                case 'getHealth': {
                    const healthStart = Date.now();
                    const tierStats = this.getTierIndexStats();
                    const modulesHealth = await this.modules.registry.health();
                    const auditHealth = await this.modules.auditChain.health();
                    const health: any = {
                        status: 'ok',
                        timestamp: Date.now(),
                        uptime: process.uptime(),
                        supervisor: this.supervisor.getStatus(),
                        memTable: {
                            count: this.memTable.count,
                            sizeBytes: this.memTable.sizeBytes,
                            dirtyCount: this.memTable.dirtyCount,
                        },
                        wal: {
                            type: this.walType,
                            fsyncMode: this.walFsyncMode,
                            maxSizeMB: this.walMaxSizeMB,
                            recoveredEntries: this.recoveredEntries,
                        },
                        insights: {
                            tracked: this.modules.nativeInsight.getInsights().length,
                            recommendations: this.modules.nativeInsight.getSignalRecommendations().length,
                        },
                        tiers: {
                            warmKeys: tierStats.warmKeys,
                            coldKeys: tierStats.coldKeys,
                        },
                        auditChain: {
                            entries: Number(auditHealth.entries ?? 0),
                            lastVerifyValid: auditHealth.lastVerifyValid ?? null,
                        },
                        resilience: {
                            circuitState: this.resilience.getCircuitState(),
                            pendingOps: this.resilience.getPendingOps(),
                        },
                        modules: modulesHealth,
                    };

                    if (this.modules.promptDistiller) {
                        try {
                            health.distiller = await this.modules.promptDistiller.health();
                        } catch {
                            health.distiller = { error: 'unavailable' };
                        }
                    }

                    health.responseTimeMs = Date.now() - healthStart;
                    return { jsonrpc: '2.0', id, result: health };
                }

                case 'ping': {
                    const segments = await this.countSegmentFiles();
                    const coldSegments = await this.countColdSegmentFiles();
                    const tierStats = this.getTierIndexStats();
                    return {
                        jsonrpc: '2.0',
                        id,
                        result: {
                            status: 'ok',
                            uptime: process.uptime(),
                            count: this.memTable.count,
                            memtableSize: this.memTable.sizeBytes,
                            memtable_size: this.memTable.sizeBytes,
                            dirtyCount: this.memTable.dirtyCount,
                            recoveredEntries: this.recoveredEntries,
                            walType: this.walType,
                            walFsyncMode: this.walFsyncMode,
                            walFsyncOnCommit: this.walFsyncOnCommit,
                            walCheckpointEveryOps: this.walCheckpointEveryOps,
                            walCheckpointEveryMs: this.walCheckpointEveryMs,
                            walMaxSizeMB: this.walMaxSizeMB,
                            segments,
                            coldSegments,
                            tiers: {
                                hot: tierStats.hotKeys,
                                warmSegments: segments,
                                coldSegments,
                            },
                            tierIndex: {
                                warmKeys: tierStats.warmKeys,
                                coldKeys: tierStats.coldKeys,
                            },
                            insightsTracked: this.modules.nativeInsight.getInsights().length,
                            supervisorState: this.supervisor.getState(),
                        },
                    };
                }

                default:
                    return { jsonrpc: '2.0', id, error: { code: -32601, message: 'Method not found' } };
            }
        } catch (e: any) {
            return { jsonrpc: '2.0', id, error: { code: -32603, message: e.message } };
        }
    }
}

import * as fs from 'fs/promises';
import * as path from 'path';
import { existsSync } from 'fs';
import { isHiddenSystemKey, isSystemKey, isTombstoneKey, makeTombstoneKey, parseTombstoneTarget } from './system-keys.js';

export type StateIndexTier = 'hot' | 'warm' | 'cold';
export type StateIndexScanMode = 'current';

export interface StateIndexEntryFields {
    [key: string]: number | string;
}

export interface StateIndexEntry {
    key: string;
    timestamp: number;
    deleted: boolean;
    tier: StateIndexTier;
    segmentRef: string | null;
    fields?: StateIndexEntryFields;
    system: boolean;
    updatedAt: number;
}

export interface StateIndexScanOptions {
    tiers?: 'all' | StateIndexTier[];
    includeSystem?: boolean;
    limit?: number;
    cursor?: string | null;
    mode?: StateIndexScanMode;
}

export interface StateIndexScanItem {
    key: string;
    fields: StateIndexEntryFields;
    tier: StateIndexTier;
    timestamp: number;
}

export interface StateIndexScanResult {
    items: StateIndexScanItem[];
    nextCursor: string | null;
}

interface StateIndexFileData {
    version: 1;
    entries: StateIndexEntry[];
}

interface RecordMutationMeta {
    timestamp?: number;
    tier?: StateIndexTier;
    segmentRef?: string | null;
}

const STATE_INDEX_VERSION = 1 as const;

export class StateIndex {
    private readonly filePath: string;
    private readonly entries = new Map<string, StateIndexEntry>();
    private sortedKeys: string[] = [];

    constructor(filePath: string) {
        this.filePath = filePath;
    }

    async load(): Promise<void> {
        if (!existsSync(this.filePath)) {
            this.entries.clear();
            this.rebuildSortedKeys();
            return;
        }

        const raw = await fs.readFile(this.filePath, 'utf8');
        let parsed: StateIndexFileData;
        try {
            parsed = JSON.parse(raw) as StateIndexFileData;
        } catch (err: any) {
            throw new Error(`StateIndex parse error: ${err.message}`);
        }

        if (parsed.version !== STATE_INDEX_VERSION || !Array.isArray(parsed.entries)) {
            throw new Error('StateIndex version mismatch or malformed payload');
        }

        this.entries.clear();
        for (const entry of parsed.entries) {
            if (!entry || typeof entry.key !== 'string') continue;
            this.entries.set(entry.key, {
                key: entry.key,
                timestamp: Number(entry.timestamp || 0),
                deleted: Boolean(entry.deleted),
                tier: entry.tier === 'warm' || entry.tier === 'cold' ? entry.tier : 'hot',
                segmentRef: entry.segmentRef ?? null,
                fields: entry.fields ? { ...entry.fields } : undefined,
                system: Boolean(entry.system || isSystemKey(entry.key)),
                updatedAt: Number(entry.updatedAt || Date.now()),
            });
        }
        this.rebuildSortedKeys();
    }

    async save(): Promise<void> {
        await fs.mkdir(path.dirname(this.filePath), { recursive: true });
        const tmpPath = `${this.filePath}.tmp`;
        const payload: StateIndexFileData = {
            version: STATE_INDEX_VERSION,
            entries: Array.from(this.entries.values()).sort((a, b) => a.key.localeCompare(b.key)),
        };
        await fs.writeFile(tmpPath, JSON.stringify(payload, null, 2), 'utf8');
        await fs.rename(tmpPath, this.filePath);
    }

    clear(): void {
        this.entries.clear();
        this.rebuildSortedKeys();
    }

    getEntry(key: string): StateIndexEntry | null {
        const entry = this.entries.get(key);
        return entry ? this.cloneEntry(entry) : null;
    }

    has(key: string): boolean {
        return this.entries.has(key);
    }

    getVisible(key: string, includeSystem: boolean = false): StateIndexEntry | null {
        const entry = this.entries.get(key);
        if (!entry) return null;
        if (entry.deleted) return null;
        if (!includeSystem && isHiddenSystemKey(entry.key)) return null;
        if (!entry.fields) return null;
        return this.cloneEntry(entry);
    }

    recordPut(key: string, fields: StateIndexEntryFields, meta: RecordMutationMeta = {}): void {
        const timestamp = meta.timestamp ?? Date.now();
        const tier = meta.tier ?? 'hot';
        const segmentRef = meta.segmentRef ?? null;
        const now = Date.now();
        const prev = this.entries.get(key);
        if (prev && timestamp < prev.timestamp) {
            return;
        }

        const next: StateIndexEntry = {
            key,
            timestamp,
            deleted: false,
            tier,
            segmentRef,
            fields: { ...fields },
            system: isSystemKey(key),
            updatedAt: now,
        };
        this.entries.set(key, next);

        if (isTombstoneKey(key)) {
            const target = parseTombstoneTarget(key);
            if (target) {
                this.recordDeletedTarget(target, timestamp, tier, segmentRef);
            }
        }

        this.rebuildSortedKeys();
    }

    recordDelete(targetKey: string, meta: RecordMutationMeta = {}): { tombstoneKey: string; tombstoneFields: StateIndexEntryFields } {
        const timestamp = meta.timestamp ?? Date.now();
        const tier = meta.tier ?? 'hot';
        const segmentRef = meta.segmentRef ?? null;
        const tombstoneKey = makeTombstoneKey(targetKey);
        const tombstoneFields: StateIndexEntryFields = {
            target_key: targetKey,
            deleted_at_ms: timestamp,
        };

        this.recordPut(tombstoneKey, tombstoneFields, { timestamp, tier, segmentRef });
        this.recordDeletedTarget(targetKey, timestamp, tier, segmentRef);
        this.rebuildSortedKeys();

        return { tombstoneKey, tombstoneFields };
    }

    applyWALDelete(targetKey: string, timestamp: number = Date.now()): void {
        this.recordDeletedTarget(targetKey, timestamp, 'hot', null);
        this.rebuildSortedKeys();
    }

    reclassifyTier(keys: Iterable<string>, tier: StateIndexTier, segmentRef: string | null): void {
        const now = Date.now();
        for (const key of keys) {
            const entry = this.entries.get(key);
            if (!entry) continue;
            entry.tier = tier;
            entry.segmentRef = segmentRef;
            entry.updatedAt = now;
        }
        this.rebuildSortedKeys();
    }

    remapSegments(segmentMap: Map<string, { tier: StateIndexTier; segmentRef: string | null }>): void {
        const now = Date.now();
        for (const entry of this.entries.values()) {
            if (!entry.segmentRef) continue;
            const replacement = segmentMap.get(entry.segmentRef);
            if (!replacement) continue;
            entry.tier = replacement.tier;
            entry.segmentRef = replacement.segmentRef;
            entry.updatedAt = now;
        }
        this.rebuildSortedKeys();
    }

    scan(prefix: string = '', options: StateIndexScanOptions = {}): StateIndexScanResult {
        const includeSystem = options.includeSystem ?? false;
        const mode = options.mode ?? 'current';
        const limit = Math.max(0, Number(options.limit ?? 0));
        const cursor = options.cursor ?? null;
        const tiers = options.tiers === 'all' || !options.tiers
            ? null
            : new Set(options.tiers);

        if (mode !== 'current') {
            throw new Error(`Unsupported scan mode: ${mode}`);
        }

        const keys = includeSystem ? this.sortedKeys : this.sortedKeys.filter((key) => !isHiddenSystemKey(key));
        const startIdx = cursor ? Math.max(0, keys.findIndex((key) => key > cursor)) : 0;
        const out: StateIndexScanItem[] = [];
        let nextCursor: string | null = null;

        for (let i = startIdx; i < keys.length; i++) {
            const key = keys[i]!;
            if (prefix && !key.startsWith(prefix)) {
                if (out.length > 0 && key.localeCompare(prefix) > 0) break;
                continue;
            }

            const entry = this.entries.get(key);
            if (!entry || entry.deleted || !entry.fields) continue;
            if (tiers && !tiers.has(entry.tier)) continue;
            if (!includeSystem && isHiddenSystemKey(key)) continue;

            out.push({
                key: entry.key,
                fields: { ...entry.fields },
                tier: entry.tier,
                timestamp: entry.timestamp,
            });

            if (limit > 0 && out.length >= limit) {
                nextCursor = entry.key;
                break;
            }
        }

        return { items: out, nextCursor };
    }

    entriesForSegment(segmentRef: string): string[] {
        return Array.from(this.entries.values())
            .filter((entry) => entry.segmentRef === segmentRef)
            .map((entry) => entry.key);
    }

    removeEntriesForSegment(segmentRef: string): void {
        let changed = false;
        for (const [key, entry] of this.entries.entries()) {
            if (entry.segmentRef !== segmentRef) continue;
            this.entries.delete(key);
            changed = true;
        }
        if (changed) this.rebuildSortedKeys();
    }

    snapshotEntries(): StateIndexEntry[] {
        return Array.from(this.entries.values()).map((entry) => this.cloneEntry(entry));
    }

    private recordDeletedTarget(targetKey: string, timestamp: number, tier: StateIndexTier, segmentRef: string | null): void {
        const now = Date.now();
        const prev = this.entries.get(targetKey);
        if (prev && timestamp < prev.timestamp) return;
        this.entries.set(targetKey, {
            key: targetKey,
            timestamp,
            deleted: true,
            tier,
            segmentRef,
            fields: undefined,
            system: isSystemKey(targetKey),
            updatedAt: now,
        });
    }

    private rebuildSortedKeys(): void {
        this.sortedKeys = Array.from(this.entries.keys()).sort((a, b) => a.localeCompare(b));
    }

    private cloneEntry(entry: StateIndexEntry): StateIndexEntry {
        return {
            ...entry,
            fields: entry.fields ? { ...entry.fields } : undefined,
        };
    }
}

/**
 * GICSSupervisor — Phase 5: Auto-restart + DEGRADED mode
 *
 * Manages daemon subsystem lifecycle with health checks,
 * exponential backoff restarts, and degraded fallback.
 */

export type SupervisorState = 'STARTING' | 'HEALTHY' | 'RESTARTING' | 'DEGRADED';

export interface BufferedWrite {
    seq: number;
    key: string;
    fields: Record<string, number | string>;
    timestamp: number;
}

export interface SupervisorConfig {
    healthCheckIntervalMs?: number;      // default: 10000
    maxRestartsBeforeDegraded?: number;  // default: 5
    restartWindowMs?: number;            // default: 300000 (5 min)
    backoffBaseMs?: number;              // default: 1000
    backoffMaxMs?: number;               // default: 16000
}

export interface SubsystemHealthCheck {
    checkMemTable: () => boolean;
    checkWAL: () => boolean;
    restartSubsystem: () => Promise<boolean>;
}

export class GICSSupervisor {
    private state: SupervisorState = 'STARTING';
    private healthCheckTimer: ReturnType<typeof setInterval> | null = null;
    private readonly healthCheckIntervalMs: number;
    private readonly maxRestarts: number;
    private readonly restartWindowMs: number;
    private readonly backoffBaseMs: number;
    private readonly backoffMaxMs: number;
    private restartTimestamps: number[] = [];
    private consecutiveFailures = 0;
    private readonly buffer: BufferedWrite[] = [];
    private bufferSeq = 0;
    private readonly transitions: Array<{ from: SupervisorState; to: SupervisorState; timestamp: number; reason: string }> = [];
    private healthChecks: SubsystemHealthCheck | null = null;
    private restartInProgress = false;

    constructor(config: SupervisorConfig = {}) {
        this.healthCheckIntervalMs = config.healthCheckIntervalMs ?? 10_000;
        this.maxRestarts = config.maxRestartsBeforeDegraded ?? 5;
        this.restartWindowMs = config.restartWindowMs ?? 300_000;
        this.backoffBaseMs = config.backoffBaseMs ?? 1000;
        this.backoffMaxMs = config.backoffMaxMs ?? 16_000;
    }

    registerHealthChecks(checks: SubsystemHealthCheck): void {
        this.healthChecks = checks;
    }

    start(): void {
        this.transition('HEALTHY', 'supervisor started');
        this.healthCheckTimer = setInterval(() => this.performHealthCheck(), this.healthCheckIntervalMs);
    }

    stop(): void {
        if (this.healthCheckTimer) {
            clearInterval(this.healthCheckTimer);
            this.healthCheckTimer = null;
        }
    }

    getState(): SupervisorState {
        return this.state;
    }

    getStatus(): {
        state: SupervisorState;
        consecutiveFailures: number;
        bufferedWrites: number;
        transitions: Array<{ from: SupervisorState; to: SupervisorState; timestamp: number; reason: string }>;
    } {
        return {
            state: this.state,
            consecutiveFailures: this.consecutiveFailures,
            bufferedWrites: this.buffer.length,
            transitions: [...this.transitions],
        };
    }

    isDegraded(): boolean {
        return this.state === 'DEGRADED';
    }

    bufferWrite(key: string, fields: Record<string, number | string>): BufferedWrite {
        const entry: BufferedWrite = {
            seq: ++this.bufferSeq,
            key,
            fields: { ...fields },
            timestamp: Date.now(),
        };
        this.buffer.push(entry);
        return entry;
    }

    /**
     * Flush buffered writes post-recovery. Returns writes that were applied
     * and writes that were discarded due to WAL conflicts.
     */
    flushBuffer(walHasKey: (key: string) => boolean, applyWrite: (key: string, fields: Record<string, number | string>) => void): {
        applied: number;
        discarded: number;
        discardedKeys: string[];
    } {
        let applied = 0;
        let discarded = 0;
        const discardedKeys: string[] = [];

        for (const entry of this.buffer) {
            if (walHasKey(entry.key)) {
                // WAL wins — discard buffered write
                discarded++;
                discardedKeys.push(entry.key);
                console.log(`[Supervisor] Conflict: WAL wins for key="${entry.key}", buffer write discarded.`);
            } else {
                applyWrite(entry.key, entry.fields);
                applied++;
            }
        }

        this.buffer.length = 0;
        this.bufferSeq = 0;
        return { applied, discarded, discardedKeys };
    }

    async resetDegraded(): Promise<boolean> {
        if (this.state !== 'DEGRADED') return false;
        this.consecutiveFailures = 0;
        this.restartTimestamps = [];
        this.transition('STARTING', 'manual reset from DEGRADED');

        if (this.healthChecks) {
            const ok = await this.healthChecks.restartSubsystem();
            if (ok) {
                this.transition('HEALTHY', 'subsystem restarted after manual reset');
                return true;
            }
            this.transition('DEGRADED', 'restart failed after manual reset');
            return false;
        }

        this.transition('HEALTHY', 'manual reset (no health checks registered)');
        return true;
    }

    getTransitions(): Array<{ from: SupervisorState; to: SupervisorState; timestamp: number; reason: string }> {
        return [...this.transitions];
    }

    private transition(to: SupervisorState, reason: string): void {
        const from = this.state;
        if (from === to) return;
        this.state = to;
        const ts = Date.now();
        this.transitions.push({ from, to, timestamp: ts, reason });
        const level = to === 'DEGRADED' ? 'error' : 'log';
        console[level](`[Supervisor] ${from} -> ${to}: ${reason} (${new Date(ts).toISOString()})`);
    }

    private async performHealthCheck(): Promise<void> {
        if (this.state === 'DEGRADED' || this.restartInProgress) return;
        if (!this.healthChecks) return;

        const memOk = this.healthChecks.checkMemTable();
        const walOk = this.healthChecks.checkWAL();

        if (memOk && walOk) {
            if (this.state === 'RESTARTING') {
                this.transition('HEALTHY', 'health check passed after restart');
            }
            this.consecutiveFailures = 0;
            return;
        }

        // Subsystem failure detected
        this.consecutiveFailures++;
        const now = Date.now();
        this.restartTimestamps.push(now);
        // Prune timestamps outside the restart window
        this.restartTimestamps = this.restartTimestamps.filter(t => now - t < this.restartWindowMs);

        if (this.restartTimestamps.length >= this.maxRestarts) {
            this.transition('DEGRADED', `${this.maxRestarts} restarts in ${this.restartWindowMs / 1000}s window`);
            return;
        }

        this.transition('RESTARTING', `subsystem failure (memOk=${memOk}, walOk=${walOk})`);
        await this.attemptRestart();
    }

    private async attemptRestart(): Promise<void> {
        if (!this.healthChecks) return;
        this.restartInProgress = true;

        const delay = Math.min(
            this.backoffBaseMs * Math.pow(2, this.consecutiveFailures - 1),
            this.backoffMaxMs
        );

        await new Promise(r => setTimeout(r, delay));

        try {
            const ok = await this.healthChecks.restartSubsystem();
            if (ok) {
                this.transition('HEALTHY', `restart succeeded after ${delay}ms backoff`);
                this.consecutiveFailures = 0;
            }
            // If not ok, next health check will detect it
        } catch (err) {
            console.error(`[Supervisor] Restart attempt failed:`, err);
        } finally {
            this.restartInProgress = false;
        }
    }
}

import * as fs from 'node:fs/promises';
import { createWriteStream, existsSync, readFileSync, WriteStream } from 'node:fs';
import * as path from 'node:path';
import { createHash } from 'node:crypto';

export enum Operation {
    PUT = 0x01,
    DELETE = 0x02
}

export type WALPayload = Record<string, number | string>;

export type WALType = 'binary' | 'jsonl';
export type WALFsyncMode = 'strict' | 'best_effort';

export interface WALProviderOptions {
    fsyncMode?: WALFsyncMode;
    fsyncOnCommit?: boolean;
    checkpointEveryOps?: number;
    checkpointEveryMs?: number;
    maxWalSizeMB?: number;
}

export interface WALProvider {
    append(op: Operation, key: string, payload: WALPayload): Promise<void>;
    replay(handler: (op: Operation, key: string, payload: WALPayload) => void): Promise<void>;
    truncate(): Promise<void>;
    close(): Promise<void>;
}

const CRC_TABLE = new Uint32Array(256);
for (let i = 0; i < 256; i++) {
    let c = i;
    for (let j = 0; j < 8; j++) {
        c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
    }
    CRC_TABLE[i] = c;
}

function crc32(buffer: Buffer): number {
    let crc = 0xFFFFFFFF;
    for (const byte of buffer) {
        crc = (crc >>> 8) ^ CRC_TABLE[(crc ^ byte) & 0xFF];
    }
    return (crc ^ 0xFFFFFFFF) >>> 0;
}

function sha256Hex(raw: string): string {
    return createHash('sha256').update(raw).digest('hex');
}

function isIgnorableFsyncError(error: unknown): boolean {
    if (!(error instanceof Error)) return false;
    const maybeErrno = error as NodeJS.ErrnoException;
    return maybeErrno.code === 'EPERM' || maybeErrno.code === 'EINVAL' || maybeErrno.code === 'ENOTSUP';
}

function stableStringify(value: unknown): string {
    if (value === null || typeof value !== 'object') return JSON.stringify(value);
    if (Array.isArray(value)) return `[${value.map(stableStringify).join(',')}]`;
    const obj = value as Record<string, unknown>;
    const keys = Object.keys(obj).sort((a, b) => a.localeCompare(b));
    return '{' + keys.map((k) => JSON.stringify(k) + ':' + stableStringify(obj[k])).join(',') + '}';
}

type StateEntry = { lsn: bigint; payload: WALPayload };
type StateMap = Map<string, StateEntry>;

interface V2Checkpoint {
    version: 2;
    lsn: string;
    timestamp: number;
    sha256: string;
    state: Record<string, WALPayload>;
}

const BIN_MAGIC = Buffer.from('GWV2', 'ascii');
const BIN_VERSION = 2;

abstract class BaseWALProvider implements WALProvider {
    protected readonly filePath: string;
    protected readonly checkpointPath: string;
    protected writeStream: WriteStream | null = null;
    protected readonly fsyncMode: WALFsyncMode;
    protected readonly fsyncOnCommit: boolean;
    protected readonly checkpointEveryOps: number;
    protected readonly checkpointEveryMs: number;
    protected readonly maxWalSizeBytes: number;

    protected lastLsn: bigint = 0n;
    protected opsSinceCheckpoint = 0;
    protected lastCheckpointAt = 0;
    protected state: StateMap = new Map();
    private initPromise: Promise<void> | null = null;
    private fsyncWarningLogged = false;
    private mutationQueue: Promise<void> = Promise.resolve();

    constructor(filePath: string, options: WALProviderOptions = {}) {
        this.filePath = filePath;
        this.checkpointPath = `${filePath}.ckpt`;
        this.fsyncMode = options.fsyncMode ?? 'best_effort';
        this.fsyncOnCommit = options.fsyncOnCommit ?? true;
        this.checkpointEveryOps = Math.max(1, options.checkpointEveryOps ?? 500);
        this.checkpointEveryMs = Math.max(1000, options.checkpointEveryMs ?? 30000);
        this.maxWalSizeBytes = Math.max(0.001, options.maxWalSizeMB ?? 50) * 1024 * 1024;
    }

    protected async ensureInitialized(): Promise<void> {
        this.initPromise ??= this.initialize();
            // removed
        // removed
        await this.initPromise;
    }

    private async initialize(): Promise<void> {
        await fs.mkdir(path.dirname(this.filePath), { recursive: true });
        await this.ensureWalReady();
        await this.loadStateFromWal();
        this.lastCheckpointAt = Date.now();
    }

    protected abstract ensureWalReady(): Promise<void>;
    protected abstract loadStateFromWal(): Promise<void>;
    protected abstract appendEntry(lsn: bigint, op: Operation, key: string, payload: WALPayload, timestamp: number): Promise<void>;
    protected abstract replayTail(afterLsn: bigint, handler: (op: Operation, key: string, payload: WALPayload, lsn: bigint) => void): Promise<void>;
    protected abstract compactToState(): Promise<void>;

    protected async ensureOpen(): Promise<void> {
        this.writeStream ??= createWriteStream(this.filePath, { flags: 'a' });
    }

    protected async closeStream(): Promise<void> {
        if (!this.writeStream) return;
        await new Promise<void>((resolve, reject) => {
            this.writeStream!.end((err?: Error | null) => {
                if (err) reject(err);
                else resolve();
            });
        });
        this.writeStream = null;
    }

    private async enqueueMutation<T>(task: () => Promise<T>): Promise<T> {
        const run = this.mutationQueue.then(task, task);
        this.mutationQueue = run.then(() => undefined, () => undefined);
        return run;
    }

    protected async fsyncFile(): Promise<void> {
        if (!this.fsyncOnCommit) return;
        const handle = await fs.open(this.filePath, 'r');
        try {
            await handle.sync();
        } catch (error) {
            if (this.fsyncMode === 'strict' || !isIgnorableFsyncError(error)) {
                throw error;
            }
            if (!this.fsyncWarningLogged) {
                this.fsyncWarningLogged = true;
                console.warn('[WAL] fsync not supported/allowed on this filesystem. Continuing without durable sync.');
            }
        } finally {
            await handle.close();
        }
    }

    protected applyState(op: Operation, key: string, payload: WALPayload, lsn: bigint): void {
        if (op === Operation.PUT) {
            this.state.set(key, { lsn, payload: { ...payload } });
        } else if (op === Operation.DELETE) {
            this.state.delete(key);
        }
    }

    protected async maybeCheckpointAndCompact(): Promise<void> {
        const now = Date.now();
        const shouldCheckpoint =
            this.opsSinceCheckpoint >= this.checkpointEveryOps ||
            now - this.lastCheckpointAt >= this.checkpointEveryMs;

        if (!shouldCheckpoint) return;

        const orderedState: Record<string, WALPayload> = {};
        for (const key of Array.from(this.state.keys()).sort((a, b) => a.localeCompare(b))) {
            orderedState[key] = { ...this.state.get(key)!.payload };
        }

        const stateRaw = stableStringify(orderedState);
        const checkpoint: V2Checkpoint = {
            version: 2,
            lsn: this.lastLsn.toString(),
            timestamp: now,
            sha256: sha256Hex(stateRaw),
            state: orderedState
        };
        await fs.appendFile(this.checkpointPath, `${JSON.stringify(checkpoint)}\n`, 'utf8');

        this.opsSinceCheckpoint = 0;
        this.lastCheckpointAt = now;

        const st = await fs.stat(this.filePath).catch(() => null);
        if (st && st.size > this.maxWalSizeBytes) {
            await this.compactToState();
        }
    }

    protected async loadCheckpoint(): Promise<{ lsn: bigint; state: Record<string, WALPayload> } | null> {
        if (!existsSync(this.checkpointPath)) return null;
        const raw = await fs.readFile(this.checkpointPath, 'utf8');
        const lines = raw.split('\n').map((x) => x.trim()).filter(Boolean);
        for (let i = lines.length - 1; i >= 0; i--) {
            try {
                const parsed = JSON.parse(lines[i]) as V2Checkpoint;
                if (parsed.version !== 2 || !parsed.state || !parsed.sha256) continue;
                const computed = sha256Hex(stableStringify(parsed.state));
                if (computed !== parsed.sha256) {
                    console.warn('[WAL] Invalid checkpoint hash detected. Falling back to previous checkpoint.');
                    continue;
                }
                return { lsn: BigInt(parsed.lsn), state: parsed.state };
            } catch {
                console.warn('[WAL] Invalid checkpoint entry. Falling back to previous checkpoint.');
            }
        }
        return null;
    }

    async append(op: Operation, key: string, payload: WALPayload): Promise<void> {
        await this.enqueueMutation(async () => {
            await this.ensureInitialized();
            await this.ensureOpen();

            const nextLsn = this.lastLsn + 1n;
            const ts = Date.now();
            await this.appendEntry(nextLsn, op, key, payload, ts);
            await this.fsyncFile();

            this.lastLsn = nextLsn;
            this.opsSinceCheckpoint++;
            this.applyState(op, key, payload, nextLsn);
            await this.maybeCheckpointAndCompact();
        });
    }

    async replay(handler: (op: Operation, key: string, payload: WALPayload) => void): Promise<void> {
        await this.ensureInitialized();

        const checkpoint = await this.loadCheckpoint();
        let checkpointLsn = 0n;

        if (checkpoint) {
            checkpointLsn = checkpoint.lsn;
            const ordered = Object.keys(checkpoint.state).sort((a, b) => a.localeCompare(b));
            for (const key of ordered) {
                handler(Operation.PUT, key, checkpoint.state[key]);
            }
        }

        await this.replayTail(checkpointLsn, (op, key, payload) => {
            handler(op, key, payload);
        });
    }

    async truncate(): Promise<void> {
        await this.enqueueMutation(async () => {
            await this.ensureInitialized();
            await this.closeStream();
            await fs.writeFile(this.filePath, '');
            await fs.writeFile(this.checkpointPath, '');
            this.lastLsn = 0n;
            this.opsSinceCheckpoint = 0;
            this.state.clear();
        });
    }

    async close(): Promise<void> {
        await this.enqueueMutation(async () => {
            await this.closeStream();
        });
    }
}

type BinaryParsedEntry = {
    op: Operation;
    key: string;
    payload: WALPayload;
    lsn: bigint;
};

function parseBinaryV1Entries(buffer: Buffer): BinaryParsedEntry[] {
    const out: BinaryParsedEntry[] = [];
    let offset = 0;
    let lsn = 0n;

    while (offset < buffer.length) {
        const start = offset;
        if (offset + 1 + 2 > buffer.length) break;
        const op = buffer.readUInt8(offset++);
        const keyLen = buffer.readUInt16LE(offset);
        offset += 2;
        if (offset + keyLen + 4 > buffer.length) break;
        const key = buffer.toString('utf8', offset, offset + keyLen);
        offset += keyLen;
        const valLen = buffer.readUInt32LE(offset);
        offset += 4;
        if (offset + valLen + 4 > buffer.length) break;
        const payloadRaw = buffer.toString('utf8', offset, offset + valLen);
        offset += valLen;
        const storedCrc = buffer.readUInt32LE(offset);
        offset += 4;

        const entryBytes = buffer.subarray(start, offset - 4);
        if (crc32(entryBytes) !== storedCrc) {
            console.warn(`[WAL] CRC mismatch at offset ${start}. Skipping corrupted entry.`);
            continue;
        }

        try {
            lsn += 1n;
            out.push({ op: op as Operation, key, payload: JSON.parse(payloadRaw), lsn });
        } catch {
            console.warn(`[WAL] Failed to parse payload at offset ${start}. Skipping entry.`);
        }
    }

    return out;
}

function parseBinaryV2Entries(buffer: Buffer): BinaryParsedEntry[] {
    const out: BinaryParsedEntry[] = [];
    let offset = BIN_MAGIC.length + 1;
    while (offset < buffer.length) {
        const start = offset;
        if (offset + 8 + 8 + 1 + 2 > buffer.length) break;

        const lsn = buffer.readBigUInt64LE(offset);
        offset += 8;
        offset += 8; // timestamp
        const op = buffer.readUInt8(offset++);
        const keyLen = buffer.readUInt16LE(offset);
        offset += 2;
        if (offset + keyLen + 4 > buffer.length) break;
        const key = buffer.toString('utf8', offset, offset + keyLen);
        offset += keyLen;
        const valLen = buffer.readUInt32LE(offset);
        offset += 4;
        if (offset + valLen + 4 > buffer.length) break;
        const payloadRaw = buffer.toString('utf8', offset, offset + valLen);
        offset += valLen;
        const storedCrc = buffer.readUInt32LE(offset);
        offset += 4;

        const entryBytes = buffer.subarray(start, offset - 4);
        if (crc32(entryBytes) !== storedCrc) {
            console.warn(`[WAL] CRC mismatch at offset ${start}. Skipping corrupted entry.`);
            continue;
        }

        try {
            out.push({ op: op as Operation, key, payload: JSON.parse(payloadRaw), lsn });
        } catch {
            console.warn(`[WAL] Failed to parse v2 payload at offset ${start}. Skipping entry.`);
        }
    }
    return out;
}

export class BinaryWALProvider extends BaseWALProvider {
    protected async ensureWalReady(): Promise<void> {
        if (!existsSync(this.filePath)) {
            await fs.writeFile(this.filePath, Buffer.concat([BIN_MAGIC, Buffer.from([BIN_VERSION])]));
            return;
        }

        const st = await fs.stat(this.filePath);
        if (st.size === 0) {
            await fs.writeFile(this.filePath, Buffer.concat([BIN_MAGIC, Buffer.from([BIN_VERSION])]));
            return;
        }

        const current = await fs.readFile(this.filePath);
        const hasV2Header = current.length >= BIN_MAGIC.length + 1
            && current.subarray(0, BIN_MAGIC.length).equals(BIN_MAGIC)
            && current.readUInt8(BIN_MAGIC.length) === BIN_VERSION;

        if (!hasV2Header) {
            // v1 -> v2 migration in place
            const entries = parseBinaryV1Entries(current);
            const header = Buffer.concat([BIN_MAGIC, Buffer.from([BIN_VERSION])]);
            const chunks: Buffer[] = [header];
            for (const entry of entries) {
                chunks.push(this.encodeBinaryV2(entry.lsn, Date.now(), entry.op, entry.key, entry.payload));
            }
            await fs.writeFile(this.filePath, Buffer.concat(chunks));
        }
    }

    private encodeBinaryV2(lsn: bigint, timestamp: number, op: Operation, key: string, payload: WALPayload): Buffer {
        const keyBuf = Buffer.from(key, 'utf8');
        const valBuf = Buffer.from(JSON.stringify(payload), 'utf8');
        const bodyLen = 8 + 8 + 1 + 2 + keyBuf.length + 4 + valBuf.length;
        const body = Buffer.alloc(bodyLen);
        let offset = 0;
        body.writeBigUInt64LE(lsn, offset);
        offset += 8;
        body.writeBigUInt64LE(BigInt(timestamp), offset);
        offset += 8;
        body.writeUInt8(op, offset++);
        body.writeUInt16LE(keyBuf.length, offset);
        offset += 2;
        keyBuf.copy(body, offset);
        offset += keyBuf.length;
        body.writeUInt32LE(valBuf.length, offset);
        offset += 4;
        valBuf.copy(body, offset);

        const out = Buffer.alloc(body.length + 4);
        body.copy(out);
        out.writeUInt32LE(crc32(body), body.length);
        return out;
    }

    protected async loadStateFromWal(): Promise<void> {
        if (!existsSync(this.filePath)) return;
        const raw = await fs.readFile(this.filePath);
        if (raw.length === 0) return;

        const entries = parseBinaryV2Entries(raw);
        for (const e of entries) {
            if (e.lsn > this.lastLsn) this.lastLsn = e.lsn;
            this.applyState(e.op, e.key, e.payload, e.lsn);
        }
    }

    protected async appendEntry(lsn: bigint, op: Operation, key: string, payload: WALPayload, timestamp: number): Promise<void> {
        const encoded = this.encodeBinaryV2(lsn, timestamp, op, key, payload);
        await new Promise<void>((resolve, reject) => {
            this.writeStream!.write(encoded, (err) => {
                if (err) reject(err);
                else resolve();
            });
        });
    }

    protected async replayTail(afterLsn: bigint, handler: (op: Operation, key: string, payload: WALPayload, lsn: bigint) => void): Promise<void> {
        if (!existsSync(this.filePath)) return;
        const raw = await fs.readFile(this.filePath);
        if (raw.length === 0) return;
        const entries = parseBinaryV2Entries(raw);
        for (const e of entries) {
            if (e.lsn <= afterLsn) continue;
            handler(e.op, e.key, e.payload, e.lsn);
        }
    }

    protected async compactToState(): Promise<void> {
        if (this.writeStream) {
            await this.closeStream();
        }
        const tempPath = `${this.filePath}.tmp`;
        const chunks: Buffer[] = [Buffer.concat([BIN_MAGIC, Buffer.from([BIN_VERSION])])];
        const entries = Array.from(this.state.entries())
            .map(([key, value]) => ({ key, ...value }))
            .sort((a, b) => (a.lsn < b.lsn ? -1 : 1));
        for (const e of entries) {
            chunks.push(this.encodeBinaryV2(e.lsn, Date.now(), Operation.PUT, e.key, e.payload));
        }
        await fs.writeFile(tempPath, Buffer.concat(chunks));
        await fs.rename(tempPath, this.filePath);
        await this.ensureOpen();
    }
}

interface JsonlV2Entry {
    version: 2;
    lsn: string;
    timestamp: number;
    op: Operation;
    key: string;
    payload: WALPayload;
    crc32: number;
}

interface JsonlV1Entry {
    op: Operation;
    key: string;
    payload: WALPayload;
    crc32: number;
}

export class JsonlWALProvider extends BaseWALProvider {
    protected async ensureWalReady(): Promise<void> {
        if (!existsSync(this.filePath)) {
            await fs.writeFile(this.filePath, `${JSON.stringify({ __wal: 'gics', version: 2 })}\n`, 'utf8');
            return;
        }

        const raw = await fs.readFile(this.filePath, 'utf8');
        if (!raw.trim()) {
            await fs.writeFile(this.filePath, `${JSON.stringify({ __wal: 'gics', version: 2 })}\n`, 'utf8');
            return;
        }

        const lines = raw.split('\n').map((x) => x.trim()).filter(Boolean);
        try {
            const first = JSON.parse(lines[0]) as Record<string, unknown>;
            if (first.__wal === 'gics' && first.version === 2) return;
        } catch {
            // falls through to migration
        }

        // v1 -> v2 migration
        let lsn = 0n;
        const out = [`${JSON.stringify({ __wal: 'gics', version: 2 })}`];
        for (const line of lines) {
            try {
                const entry = JSON.parse(line) as JsonlV1Entry;
                const base = { op: entry.op, key: entry.key, payload: entry.payload };
                const computed = crc32(Buffer.from(JSON.stringify(base), 'utf8'));
                if (computed !== entry.crc32) {
                    console.warn('[WAL] JSONL CRC mismatch. Skipping corrupted entry.');
                    continue;
                }
                lsn += 1n;
                const payload = { lsn: lsn.toString(), timestamp: Date.now(), ...base };
                const checksum = crc32(Buffer.from(stableStringify(payload), 'utf8'));
                out.push(JSON.stringify({ version: 2, ...payload, crc32: checksum }));
            } catch {
                console.warn('[WAL] Invalid JSONL entry during migration. Skipping.');
            }
        }
        await fs.writeFile(this.filePath, `${out.join('\n')}\n`, 'utf8');
    }

    private parseAllV2(): Array<{ op: Operation; key: string; payload: WALPayload; lsn: bigint }> {
        if (!existsSync(this.filePath)) return [];
        const raw = readFileSync(this.filePath, 'utf8');
        const lines = raw.split('\n').map((x) => x.trim()).filter(Boolean);
        const out: Array<{ op: Operation; key: string; payload: WALPayload; lsn: bigint }> = [];
        for (const line of lines) {
            try {
                const parsed = JSON.parse(line) as Record<string, unknown>;
                if (parsed.__wal === 'gics') continue;
                const entry = parsed as unknown as JsonlV2Entry;
                const base = {
                    lsn: entry.lsn,
                    timestamp: entry.timestamp,
                    op: entry.op,
                    key: entry.key,
                    payload: entry.payload
                };
                const computed = crc32(Buffer.from(stableStringify(base), 'utf8'));
                if (computed !== entry.crc32) {
                    console.warn('[WAL] JSONL CRC mismatch. Skipping corrupted entry.');
                    continue;
                }
                out.push({ op: entry.op, key: entry.key, payload: entry.payload, lsn: BigInt(entry.lsn) });
            } catch {
                console.warn('[WAL] Invalid JSONL entry. Skipping.');
            }
        }
        return out;
    }

    protected async loadStateFromWal(): Promise<void> {
        const entries = this.parseAllV2();
        for (const e of entries) {
            if (e.lsn > this.lastLsn) this.lastLsn = e.lsn;
            this.applyState(e.op, e.key, e.payload, e.lsn);
        }
    }

    protected async appendEntry(lsn: bigint, op: Operation, key: string, payload: WALPayload, timestamp: number): Promise<void> {
        const base = { lsn: lsn.toString(), timestamp, op, key, payload };
        const line = JSON.stringify({ version: 2, ...base, crc32: crc32(Buffer.from(stableStringify(base), 'utf8')) }) + '\n';
        await new Promise<void>((resolve, reject) => {
            this.writeStream!.write(line, (err) => {
                if (err) reject(err);
                else resolve();
            });
        });
    }

    protected async replayTail(afterLsn: bigint, handler: (op: Operation, key: string, payload: WALPayload, lsn: bigint) => void): Promise<void> {
        const entries = this.parseAllV2();
        for (const e of entries) {
            if (e.lsn <= afterLsn) continue;
            handler(e.op, e.key, e.payload, e.lsn);
        }
    }

    protected async compactToState(): Promise<void> {
        if (this.writeStream) {
            await this.closeStream();
        }

        const lines: string[] = [JSON.stringify({ __wal: 'gics', version: 2 })];
        const entries = Array.from(this.state.entries())
            .map(([key, value]) => ({ key, ...value }))
            .sort((a, b) => (a.lsn < b.lsn ? -1 : 1));
        for (const e of entries) {
            const base = {
                lsn: e.lsn.toString(),
                timestamp: Date.now(),
                op: Operation.PUT,
                key: e.key,
                payload: e.payload
            };
            lines.push(JSON.stringify({ version: 2, ...base, crc32: crc32(Buffer.from(stableStringify(base), 'utf8')) }));
        }
        const tempPath = `${this.filePath}.tmp`;
        await fs.writeFile(tempPath, `${lines.join('\n')}\n`, 'utf8');
        await fs.rename(tempPath, this.filePath);
        await this.ensureOpen();
    }
}

export function createWALProvider(type: WALType, filePath: string, options: WALProviderOptions = {}): WALProvider {
    if (type === 'jsonl') {
        return new JsonlWALProvider(filePath, options);
    }
    return new BinaryWALProvider(filePath, options);
}

/**
 * GICS Utilities
 * 
 * @module gics
 * @version 1.1.0
 * @status FROZEN - Canonical implementation
 * @see docs/GICS_V1.1_SPEC.md
 * 
 * Shared functions for GICS encoding/decoding.
 */

/**
 * Encode integers with zigzag + variable-length encoding
 * Small numbers = 1 byte, larger = 2-5 bytes
 */
export function encodeVarint(values: number[]): Uint8Array {
    const buffer: number[] = [];

    for (const val of values) {
        // Zigzag encode: map signed to unsigned (negative numbers close to 0)
        const zigzag = val >= 0 ? val * 2 : (Math.abs(val) * 2) - 1;

        // Variable-length encoding
        let n = zigzag;
        while (n >= 0x80) {
            buffer.push((n % 128) | 0x80);
            n = Math.floor(n / 128);
        }
        buffer.push(n);
    }

    return new Uint8Array(buffer);
}

/**
 * Decode zigzag + variable-length integers
 */
export function decodeVarint(data: Uint8Array): number[] {
    const values: number[] = [];
    let i = 0;

    while (i < data.length) {
        let zigzag = 0;
        let p2d = 1; // Power of 2 (for shift replacement)

        while (i < data.length) {
            const byte = data[i++];
            zigzag += (byte & 0x7F) * p2d;
            if ((byte & 0x80) === 0) break;
            p2d *= 128;
        }

        // Decode zigzag
        const val = (zigzag % 2 === 0) ? (zigzag / 2) : -((zigzag + 1) / 2);
        values.push(val);
    }

    return values;
}

/**
 * RLE + Varint encoding: extremely efficient for sparse data with many zeros
 * Format: [run_length][value][run_length][value]...
 * - Run of zeros: encode as [count, 0]
 * - Run of same value: encode as [count, value]
 * - Single values: encode as [1, value]
 */
export function encodeRLE(values: number[]): Uint8Array {
    if (values.length === 0) return new Uint8Array(0);

    const runs: number[] = [];
    let i = 0;

    while (i < values.length) {
        const val = values[i];
        let count = 1;

        // Count consecutive identical values
        while (i + count < values.length && values[i + count] === val && count < 255) {
            count++;
        }

        runs.push(count, val);
        i += count;
    }

    return encodeVarint(runs);
}

/**
 * Decode RLE + Varint
 */
export function decodeRLE(data: Uint8Array): number[] {
    const runs = decodeVarint(data);
    const values: number[] = [];

    // Guard: RLE runs must be pairs (count, value)
    if (runs.length % 2 !== 0) {
        console.warn('[GICS] decodeRLE: odd run count, data may be corrupted');
        // Process available pairs only
    }

    const pairCount = Math.floor(runs.length / 2);
    for (let i = 0; i < pairCount; i++) {
        const count = runs[i * 2];
        const val = runs[i * 2 + 1];
        for (let j = 0; j < count; j++) {
            values.push(val);
        }
    }

    return values;
}

export function decodeVarintAt(data: Uint8Array, start: number): { values: number[], nextPos: number } {
    let i = start;
    let zigzag = 0;
    let p2d = 1;

    while (true) {
        if (i >= data.length) throw new RangeError("Truncated varint");
        const byte = data[i++];
        zigzag += (byte & 0x7F) * p2d;
        if ((byte & 0x80) === 0) break;
        p2d *= 128;
    }

    const val = (zigzag % 2 === 0) ? (zigzag / 2) : -((zigzag + 1) / 2);
    return { values: [val], nextPos: i };
}

export function decodeVarintN(data: Uint8Array, start: number, n: number): { values: number[], nextPos: number } {
    const values: number[] = [];
    let i = start;

    for (let count = 0; count < n; count++) { // Removed i < data.length check from loop condition to catch it inside
        let zigzag = 0;
        let p2d = 1;
        while (true) {
            if (i >= data.length) throw new RangeError("Truncated varint");
            const byte = data[i++];
            zigzag += (byte & 0x7F) * p2d;
            if ((byte & 0x80) === 0) break;
            p2d *= 128;
        }
        const val = (zigzag % 2 === 0) ? (zigzag / 2) : -((zigzag + 1) / 2);
        values.push(val);
    }

    return { values, nextPos: i };
}

/**
 * Wait for N ms
 */
export const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

import * as os from 'node:os';
import { createHash } from 'node:crypto';
import {
    InferenceKeys,
    InferenceStateStore,
    type CandidateOutcomeStats,
    type ScopeProfile,
    type StoredDecisionRecord,
    type StoredFeedbackRecord,
    type StoredPolicyRecord
} from './state-store.js';
import type { InferenceDecision, InferenceRequest, RecommendationQuery } from '../daemon/module-registry.js';

interface CandidateInput {
    id: string;
    payload: Record<string, unknown>;
}

interface ScoredCandidate {
    id: string;
    score: number;
    confidence: number;
    basis: string[];
    candidate: Record<string, unknown>;
}

export interface InferenceArtifacts {
    decision: InferenceDecision;
    decisionRecord: StoredDecisionRecord;
    profile: ScopeProfile;
    policy: StoredPolicyRecord;
}

export interface OutcomeArtifacts {
    feedback: StoredFeedbackRecord;
    stats: CandidateOutcomeStats;
    profile: ScopeProfile;
    policy: StoredPolicyRecord | null;
}

function stableId(raw: unknown): string {
    return createHash('sha256').update(JSON.stringify(raw)).digest('hex').slice(0, 16);
}

function clamp(value: number, min: number = 0, max: number = 1): number {
    return Math.max(min, Math.min(max, value));
}

function toNumber(value: unknown, fallback: number = 0): number {
    const num = Number(value);
    return Number.isFinite(num) ? num : fallback;
}

function feedbackScore(result: string | undefined, success: boolean): number {
    if (success) return 1;
    switch (String(result ?? '').toLowerCase()) {
        case 'partial':
        case 'retry':
            return 0.35;
        case 'timeout':
        case 'error':
        case 'fail':
        case 'failed':
            return 0;
        default:
            return success ? 1 : 0.1;
    }
}

export class GICSInferenceEngine {
    private readonly hostFingerprint: string;
    private readonly engineVersion = 'gics-inference-engine-v1';
    private readonly policyVersion = 'gics-infer-policy-v1';

    constructor(private readonly store: InferenceStateStore, private readonly defaultScope: string) {
        this.hostFingerprint = `${os.hostname()}|${os.platform()}|${os.arch()}`;
    }

    async load(): Promise<void> {
        await this.store.load();
        this.store.setRuntimeMetadata({ engineVersion: this.engineVersion });
    }

    async save(): Promise<void> {
        await this.store.save();
    }

    recordWrite(scope: string, payloadBytes: number): ScopeProfile {
        return this.store.recordWrite(scope, this.hostFingerprint, payloadBytes);
    }

    recordRead(scope: string, latencyMs: number = 0): ScopeProfile {
        return this.store.recordRead(scope, this.hostFingerprint, latencyMs);
    }

    recordScan(scope: string): ScopeProfile {
        return this.store.recordScan(scope, this.hostFingerprint);
    }

    recordFlush(scope: string, compressionRatio?: number): ScopeProfile {
        return this.store.recordFlush(scope, this.hostFingerprint, compressionRatio);
    }

    recordCompaction(scope: string): ScopeProfile {
        return this.store.recordCompaction(scope, this.hostFingerprint);
    }

    recordRotation(scope: string): ScopeProfile {
        return this.store.recordRotation(scope, this.hostFingerprint);
    }

    recordOutcome(
        domain: string,
        decisionId: string | undefined,
        context: Record<string, unknown> | undefined,
        metrics: Record<string, number> | undefined,
        result: string | undefined
    ): OutcomeArtifacts | null {
        const decision = decisionId ? this.store.getDecision(decisionId) : null;
        const { candidateId, scope, subject } = this.extractIdentifiers(context, decision);
        if (!candidateId) return null;

        const success = result === 'success' || result === 'ok' || result === 'true';
        const feedback: StoredFeedbackRecord = {
            feedbackId: `${Date.now()}|${stableId({ domain, candidateId, decisionId, scope, subject, result, metrics })}`,
            systemKey: '',
            domain,
            scope,
            subject,
            decisionId,
            candidateId,
            success,
            result: String(result ?? (success ? 'success' : 'failure')),
            metrics: { ...metrics },
            context: context ? { ...context } : undefined,
            recordedAt: Date.now(),
        };
        feedback.systemKey = InferenceKeys.buildFeedbackSystemKey(feedback.feedbackId);
        this.store.appendFeedback(feedback);

        const stats = this.store.recordOutcome(domain, candidateId, {
            success,
            latencyMs: metrics?.latencyMs,
            costScore: metrics?.costScore ?? metrics?.costUsd,
            feedbackScore: feedbackScore(result, success),
            result: feedback.result,
        });

        let profile = this.store.getProfile(scope, this.hostFingerprint);
        if (success && decision) {
            const chosen = decision.ranking.find((item) => item.id === candidateId);
            if (domain === 'compression.encode') {
                profile = this.store.updateProfile(scope, this.hostFingerprint, (draft) => {
                    draft.preferences.preferredCompressionPreset = candidateId;
                });
            } else if (domain === 'ops.provider_select') {
                profile = this.store.updateProfile(scope, this.hostFingerprint, (draft) => {
                    draft.preferences.preferredProviderId = candidateId;
                });
            } else if (domain === 'ops.plan_rank' && chosen) {
                profile = this.store.updateProfile(scope, this.hostFingerprint, (draft) => {
                    const risk = toNumber(chosen.candidate.risk, 0.5);
                    const confidence = toNumber(chosen.candidate.confidence, 0.5);
                    draft.preferences.preferredPlanBias = confidence >= (1 - risk) ? 'high_confidence' : 'low_risk';
                });
            } else if (domain === 'storage.policy') {
                profile = this.store.updateProfile(scope, this.hostFingerprint, (draft) => {
                    draft.policyHints.storageMode = candidateId;
                });
            }
        }

        const policy = this.buildPolicy(domain, scope, subject, profile, decision?.ranking.map((item) => ({
            id: item.id,
            payload: { ...item.candidate },
        })) ?? []);
        this.store.upsertPolicy(policy);

        return { feedback, stats, profile, policy };
    }

    infer(request: InferenceRequest): InferenceDecision {
        return this.inferDetailed(request).decision;
    }

    inferDetailed(request: InferenceRequest): InferenceArtifacts {
        const scope = this.resolveScope(request.context);
        const subject = request.subject ? String(request.subject) : undefined;
        const now = Date.now();
        const profile = this.store.getProfile(scope, this.hostFingerprint);
        const candidates = this.resolveCandidates(request);
        const policy = this.buildPolicy(request.domain, scope, subject, profile, candidates);
        const ranking = candidates
            .map((candidate) => this.scoreCandidate(request.domain, candidate, profile, policy))
            .sort((a, b) => b.score - a.score || a.id.localeCompare(b.id));

        const recommended = ranking[0];
        const finalizedPolicy: StoredPolicyRecord = {
            ...policy,
            recommendedCandidateId: recommended?.id,
            payload: {
                ...policy.payload,
                recommendedCandidateId: recommended?.id,
                rankingPreview: ranking.slice(0, 3).map((item) => ({
                    id: item.id,
                    score: item.score,
                    confidence: item.confidence,
                })),
            },
            generatedAt: now,
        };
        this.store.upsertPolicy(finalizedPolicy);

        const decisionId = `${request.domain}|${now}|${stableId({ scope, subject, candidates: ranking.map((item) => item.id), objective: request.objective })}`;
        const evidenceKeys = [`_infer|profile|${scope}`, finalizedPolicy.systemKey];
        const decision: InferenceDecision = {
            domain: request.domain,
            decisionId,
            ranking: ranking.map((item) => ({
                id: item.id,
                score: item.score,
                confidence: item.confidence,
                basis: item.basis,
                candidate: item.candidate,
            })),
            policyVersion: finalizedPolicy.policyVersion,
            profileVersion: `profile-v${profile.version}`,
            evidenceKeys,
            recommended: recommended ? {
                id: recommended.id,
                score: recommended.score,
                confidence: recommended.confidence,
                basis: recommended.basis,
            } : undefined,
            createdAt: now,
        };

        const decisionRecord: StoredDecisionRecord = {
            decisionId,
            systemKey: InferenceKeys.buildDecisionSystemKey(decisionId),
            domain: request.domain,
            scope,
            subject,
            recommendedId: recommended?.id,
            createdAt: now,
            policyKey: finalizedPolicy.key,
            policyVersion: finalizedPolicy.policyVersion,
            profileVersion: decision.profileVersion,
            ranking: decision.ranking.map((item) => ({
                id: item.id,
                score: item.score,
                confidence: item.confidence,
                basis: [...item.basis],
                candidate: { ...item.candidate },
            })),
            evidenceKeys,
        };
        this.store.appendDecision(decisionRecord);

        const profileHints = this.deriveProfileHints(request.domain, recommended?.id, recommended?.candidate ?? {}, finalizedPolicy.payload);
        const updatedProfile = this.store.updatePolicyHints(scope, this.hostFingerprint, profileHints);

        return {
            decision,
            decisionRecord,
            profile: updatedProfile,
            policy: finalizedPolicy,
        };
    }

    getProfile(scope: string): ScopeProfile {
        return this.store.getProfile(scope, this.hostFingerprint);
    }

    getPolicy(domain: string, scope: string, subject?: string): StoredPolicyRecord | null {
        return this.store.getPolicy(domain, scope, subject);
    }

    getPolicyByKey(policyKey: string): StoredPolicyRecord | null {
        return this.store.getPolicyByKey(policyKey);
    }

    getDecision(decisionId: string): StoredDecisionRecord | null {
        return this.store.getDecision(decisionId);
    }

    getFeedback(feedbackId: string): StoredFeedbackRecord | null {
        return this.store.getFeedback(feedbackId);
    }

    getRecommendations(query: RecommendationQuery): Array<Record<string, unknown>> {
        const limit = query.limit ?? 20;
        const decisions = this.store.getDecisions(query.domain, query.subject, limit).map((decision) => ({
            type: 'inference_decision',
            domain: decision.domain,
            scope: decision.scope,
            subject: decision.subject,
            decisionId: decision.decisionId,
            recommendedId: decision.recommendedId,
            ranking: decision.ranking,
            policyVersion: decision.policyVersion,
            profileVersion: decision.profileVersion,
            createdAt: decision.createdAt,
            evidenceKeys: decision.evidenceKeys,
        }));
        const policies = this.store.getPolicies(query.domain, this.defaultScope, query.subject, Math.max(1, Math.floor(limit / 2))).map((policy) => ({
            type: 'inference_policy',
            domain: policy.domain,
            scope: policy.scope,
            subject: policy.subject,
            policyKey: policy.key,
            policyVersion: policy.policyVersion,
            profileVersion: policy.profileVersion,
            recommendedCandidateId: policy.recommendedCandidateId,
            payload: policy.payload,
            generatedAt: policy.generatedAt,
            evidenceKeys: policy.evidenceKeys,
        }));
        return [...decisions, ...policies]
            .sort((a, b) => {
                const aTime = Number((a as { createdAt?: number; generatedAt?: number; }).createdAt ?? (a as { generatedAt?: number; }).generatedAt ?? 0);
                const bTime = Number((b as { createdAt?: number; generatedAt?: number; }).createdAt ?? (b as { generatedAt?: number; }).generatedAt ?? 0);
                return bTime - aTime;
            })
            .slice(0, limit);
    }

    getRuntimeSnapshot(): Record<string, unknown> {
        return {
            ...this.store.getRuntime(),
            ...this.store.getSummary(),
            hostFingerprint: this.hostFingerprint,
            defaultScope: this.defaultScope,
        };
    }

    private resolveScope(context: Record<string, unknown> | undefined): string {
        return typeof context?.scope === 'string' ? context.scope : this.defaultScope;
    }

    private extractIdentifiers(
        context: Record<string, unknown> | undefined,
        decision: StoredDecisionRecord | null
    ): { candidateId: string; scope: string; subject?: string } {
        let candidateId = '';
        if (typeof context?.candidateId === 'string') candidateId = context.candidateId;
        else if (typeof context?.chosenCandidateId === 'string') candidateId = context.chosenCandidateId;
        else if (typeof decision?.recommendedId === 'string') candidateId = decision.recommendedId;

        let scope = this.defaultScope;
        if (typeof context?.scope === 'string') scope = context.scope;
        else if (typeof decision?.scope === 'string') scope = decision.scope;

        let subject: string | undefined;
        if (typeof context?.subject === 'string') subject = context.subject;
        else if (typeof decision?.subject === 'string') subject = decision.subject;

        return { candidateId, scope, subject };
    }

    private resolveCandidates(request: InferenceRequest): CandidateInput[] {
        if (request.candidates?.length) {
            return request.candidates.map((candidate, index) => {
                let id = `${request.domain}-${index}`;
                if (typeof candidate.id === 'string') id = candidate.id;
                else if (typeof candidate.name === 'string') id = candidate.name;
                else if (typeof candidate.model === 'string') id = candidate.model;
                return {
                    id,
                    payload: { ...candidate },
                };
            });
        }

        switch (request.domain) {
            case 'compression.encode':
                return [
                    { id: 'balanced', payload: { preset: 'balanced' } },
                    { id: 'max_ratio', payload: { preset: 'max_ratio' } },
                    { id: 'low_latency', payload: { preset: 'low_latency' } },
                ];
            case 'storage.policy':
                return [
                    { id: 'policy.current', payload: { mode: 'current' } },
                    { id: 'policy.read_heavy', payload: { mode: 'read_heavy' } },
                    { id: 'policy.write_heavy', payload: { mode: 'write_heavy' } },
                ];
            default:
                return [];
        }
    }

    private buildPolicy(domain: string, scope: string, subject: string | undefined, profile: ScopeProfile, candidates: CandidateInput[]): StoredPolicyRecord {
        const key = InferenceKeys.buildPolicyStorageKey(domain, scope, subject);
        const base: StoredPolicyRecord = {
            key,
            systemKey: InferenceKeys.buildPolicySystemKey(domain, scope, subject),
            domain,
            scope,
            subject,
            policyVersion: `${this.policyVersion}:${domain}`,
            profileVersion: `profile-v${profile.version}`,
            generatedAt: Date.now(),
            basis: [],
            weights: {},
            thresholds: {},
            payload: {},
            evidenceKeys: [`_infer|profile|${scope}`],
        };

        switch (domain) {
            case 'compression.encode': return this.buildCompressionPolicy(profile, candidates, base);
            case 'ops.provider_select': return this.buildProviderPolicy(profile, base);
            case 'ops.plan_rank': return this.buildPlanPolicy(profile, base);
            case 'storage.policy': return this.buildStoragePolicy(profile, base);
            default:
                return {
                    ...base,
                    basis: [`candidates=${candidates.length}`],
                    weights: { bandit: 0.65, heuristic: 0.35 },
                    thresholds: {},
                    payload: {},
                };
        }
    }

    private buildCompressionPolicy(profile: ScopeProfile, candidates: CandidateInput[], base: StoredPolicyRecord): StoredPolicyRecord {
        const readHeavy = profile.stats.reads > Math.max(1, profile.stats.writes * 2);
        const ratioLow = profile.stats.avgCompressionRatio > 0 && profile.stats.avgCompressionRatio < 20;
        let suggestedPreset = profile.preferences.preferredCompressionPreset ?? 'balanced';
        if (readHeavy) suggestedPreset = 'low_latency';
        else if (ratioLow) suggestedPreset = 'max_ratio';
        return {
            ...base,
            basis: [`reads=${profile.stats.reads}`, `writes=${profile.stats.writes}`, `avgCompressionRatio=${profile.stats.avgCompressionRatio.toFixed(2)}`],
            weights: { bandit: 0.55, readPressure: readHeavy ? 0.25 : 0.08, ratioPressure: ratioLow ? 0.25 : 0.12, baseline: 0.15 },
            thresholds: { ratioLowCutoff: 20, readHeavyFactor: 2 },
            payload: { suggestedPreset, workloadClass: readHeavy ? 'read_heavy' : 'balanced', candidateCount: candidates.length },
        };
    }

    private buildProviderPolicy(profile: ScopeProfile, base: StoredPolicyRecord): StoredPolicyRecord {
        return {
            ...base,
            basis: [`preferredProvider=${profile.preferences.preferredProviderId ?? 'none'}`, `avgLatency=${profile.stats.avgReadLatencyMs.toFixed(2)}`],
            weights: { bandit: 0.5, latency: 0.3, cost: 0.2 },
            thresholds: { maxLatencyMs: 5000, maxCostScore: 1 },
            payload: { objective: 'provider_select', preferredProviderId: profile.preferences.preferredProviderId ?? null },
        };
    }

    private buildPlanPolicy(profile: ScopeProfile, base: StoredPolicyRecord): StoredPolicyRecord {
        return {
            ...base,
            basis: [`preferredPlanBias=${profile.preferences.preferredPlanBias ?? 'balanced'}`, `reads=${profile.stats.reads}`, `writes=${profile.stats.writes}`],
            weights: { bandit: 0.35, confidence: 0.3, risk: 0.2, cost: 0.15 },
            thresholds: { maxRisk: 0.65, minConfidence: 0.55 },
            payload: { objective: 'plan_rank', preferredBias: profile.preferences.preferredPlanBias ?? 'balanced' },
        };
    }

    private buildStoragePolicy(profile: ScopeProfile, base: StoredPolicyRecord): StoredPolicyRecord {
        const scanHeavy = profile.stats.scans > Math.max(1, profile.stats.writes);
        const writeHeavy = profile.stats.writes >= Math.max(1, profile.stats.reads);
        let mode = 'policy.current';
        if (scanHeavy) mode = 'policy.read_heavy';
        else if (writeHeavy) mode = 'policy.write_heavy';
        return {
            ...base,
            basis: [`scans=${profile.stats.scans}`, `writes=${profile.stats.writes}`, `flushes=${profile.stats.flushes}`],
            weights: { bandit: 0.35, scanPressure: scanHeavy ? 0.3 : 0.1, writePressure: writeHeavy ? 0.3 : 0.1, safety: 0.15 },
            thresholds: { scanHeavyCutoff: profile.stats.writes || 1, writeHeavyCutoff: profile.stats.reads || 1 },
            payload: { mode, recommendedMaxMemSizeBytes: writeHeavy ? 64 * 1024 * 1024 : 24 * 1024 * 1024, recommendedMaxDirtyCount: scanHeavy ? 1500 : 4000, recommendedWarmRetentionMs: scanHeavy ? 14 * 24 * 60 * 60 * 1000 : 30 * 24 * 60 * 60 * 1000 },
        };
    }

    private scoreCandidate(domain: string, candidate: CandidateInput, profile: ScopeProfile, policy: StoredPolicyRecord): ScoredCandidate {
        const stats = this.store.getOutcomeStats(domain, candidate.id);
        const pulls = (stats?.successes ?? 0) + (stats?.failures ?? 0);
        const banditScore = ((stats?.successes ?? 0) + 3) / (pulls + 4);
        const basis: string[] = [`bandit=${banditScore.toFixed(3)}`];
        const components: number[] = [banditScore];
        const weights: number[] = [policy.weights.bandit ?? 0.65];

        switch (domain) {
            case 'compression.encode': this.scoreCompression(candidate, policy, components, weights, basis); break;
            case 'ops.provider_select': this.scoreProvider(candidate, stats ?? null, policy, components, weights, basis); break;
            case 'ops.plan_rank': this.scorePlan(candidate, policy, components, weights, basis); break;
            case 'storage.policy': this.scoreStorage(candidate, profile, policy, components, weights, basis); break;
            default:
                components.push(clamp(0.45 + ((stats?.avgFeedbackScore ?? 0.5) * 0.5)));
                weights.push(policy.weights.heuristic ?? 0.35);
                break;
        }

        const totalWeight = Math.max(0.0001, weights.reduce((sum, current) => sum + current, 0));
        const weightedScore = components.reduce((sum, component, index) => sum + (component * weights[index]), 0);
        const score = clamp(weightedScore / totalWeight);
        const confidence = clamp(0.35 + (Math.min(pulls, 25) / 35) + ((stats?.avgFeedbackScore ?? 0) * 0.15));

        if (stats) basis.push(`outcomes=${stats.totalOutcomes}`, `success=${stats.successes}`, `feedback=${stats.avgFeedbackScore.toFixed(2)}`);

        return { id: candidate.id, score, confidence, basis, candidate: { ...candidate.payload } };
    }

    private scoreCompression(candidate: CandidateInput, policy: StoredPolicyRecord, components: number[], weights: number[], basis: string[]): void {
        const suggested = typeof policy.payload.suggestedPreset === 'string' ? policy.payload.suggestedPreset : 'balanced';

        let readMatch = 0.25;
        if (candidate.id === 'low_latency') readMatch = 1;
        else if (candidate.id === 'balanced') readMatch = 0.6;

        let ratioMatch = 0.25;
        if (candidate.id === 'max_ratio') ratioMatch = 1;
        else if (candidate.id === 'balanced') ratioMatch = 0.55;

        let baseline = 0.4;
        if (candidate.id === suggested) baseline = 1;
        else if (candidate.id === 'balanced') baseline = 0.7;

        components.push(readMatch, ratioMatch, baseline);
        weights.push(policy.weights.readPressure ?? 0.15, policy.weights.ratioPressure ?? 0.15, policy.weights.baseline ?? 0.15);
        basis.push(`suggestedPreset=${suggested}`);
    }

    private scoreProvider(candidate: CandidateInput, stats: CandidateOutcomeStats | null, policy: StoredPolicyRecord, components: number[], weights: number[], basis: string[]): void {
        const latency = toNumber(candidate.payload.latencyMs ?? candidate.payload.latency, stats?.avgLatencyMs ?? 2500);
        const cost = toNumber(candidate.payload.costScore ?? candidate.payload.cost ?? candidate.payload.costUsd, stats?.avgCostScore ?? 0.5);
        components.push(clamp(1 - (latency / Math.max(1, policy.thresholds.maxLatencyMs ?? 5000))), clamp(1 - (cost / Math.max(0.001, policy.thresholds.maxCostScore ?? 1))));
        weights.push(policy.weights.latency ?? 0.2, policy.weights.cost ?? 0.15);
        basis.push(`latency=${latency}`, `cost=${cost}`);
    }

    private scorePlan(candidate: CandidateInput, policy: StoredPolicyRecord, components: number[], weights: number[], basis: string[]): void {
        const risk = toNumber(candidate.payload.risk, 0.5);
        const confidence = toNumber(candidate.payload.confidence, 0.5);
        const cost = toNumber(candidate.payload.estimated_cost ?? candidate.payload.cost, 0.5);
        components.push(clamp(confidence), clamp(1 - risk), clamp(1 - cost));
        weights.push(policy.weights.confidence ?? 0.3, policy.weights.risk ?? 0.2, policy.weights.cost ?? 0.15);
        basis.push(`risk=${risk}`, `confidence=${confidence}`, `cost=${cost}`);
    }

    private scoreStorage(candidate: CandidateInput, profile: ScopeProfile, policy: StoredPolicyRecord, components: number[], weights: number[], basis: string[]): void {
        const mode = typeof candidate.payload.mode === 'string' ? candidate.payload.mode : candidate.id;
        const recMode = typeof policy.payload.mode === 'string' ? policy.payload.mode : 'policy.current';

        let modeScore = 0.45;
        if (mode === recMode) modeScore = 1;
        else if (mode === 'current') modeScore = 0.65;

        const scanHeavy = profile.stats.scans > Math.max(1, profile.stats.writes) ? 1 : 0.35;
        const writeHeavy = profile.stats.writes >= Math.max(1, profile.stats.reads) ? 1 : 0.35;
        const safety = candidate.id === 'policy.current' ? 1 : 0.75;

        components.push(modeScore, scanHeavy, writeHeavy, safety);
        weights.push(policy.weights.scanPressure ?? 0.2, policy.weights.scanPressure ?? 0.1, policy.weights.writePressure ?? 0.1, policy.weights.safety ?? 0.15);
        Object.assign(candidate.payload, {
            recommendedMaxMemSizeBytes: policy.payload.recommendedMaxMemSizeBytes,
            recommendedMaxDirtyCount: policy.payload.recommendedMaxDirtyCount,
            recommendedWarmRetentionMs: policy.payload.recommendedWarmRetentionMs,
        });
        basis.push(`mode=${mode}`, `recommendedMode=${recMode}`);
    }

    private deriveProfileHints(
        domain: string,
        recommendedId: string | undefined,
        recommendedCandidate: Record<string, unknown>,
        policyPayload: Record<string, unknown>
    ): ScopeProfile['policyHints'] {
        if (domain === 'compression.encode') {
            const preset = typeof policyPayload.suggestedPreset === 'string' ? policyPayload.suggestedPreset : 'balanced';
            return {
                compressionPreset: recommendedId ?? preset,
            };
        }

        if (domain === 'ops.provider_select') {
            return {
                providerId: recommendedId,
            };
        }

        if (domain === 'storage.policy') {
            const mode = typeof policyPayload.mode === 'string' ? policyPayload.mode : 'policy.current';
            return {
                storageMode: recommendedId ?? mode,
                maxMemSizeBytes: Math.floor(toNumber(recommendedCandidate.recommendedMaxMemSizeBytes ?? policyPayload.recommendedMaxMemSizeBytes, 0)),
                maxDirtyCount: toNumber(recommendedCandidate.recommendedMaxDirtyCount ?? policyPayload.recommendedMaxDirtyCount, 0),
                warmRetentionMs: toNumber(recommendedCandidate.recommendedWarmRetentionMs ?? policyPayload.recommendedWarmRetentionMs, 0),
            };
        }

        return {};
    }
}

import * as path from 'path';
import { GICSInferenceEngine } from './engine.js';
import { InferenceStateStore } from './state-store.js';
import type {
    DaemonModule,
    InferenceDecision,
    InferenceRequest,
    ModuleCompactEvent,
    ModuleContext,
    ModuleDeleteEvent,
    ModuleFlushEvent,
    ModuleOutcomeEvent,
    ModuleReadEvent,
    ModuleRotateEvent,
    ModuleWriteEvent,
    RecommendationQuery
} from '../daemon/module-registry.js';

export interface InferenceEngineModuleOptions {
    flushIntervalMs?: number;
    flushOpsThreshold?: number;
    eagerFlushOnInfer?: boolean;
    eagerFlushOnOutcome?: boolean;
}

const DEFAULT_OPTIONS: Required<InferenceEngineModuleOptions> = {
    flushIntervalMs: 1500,
    flushOpsThreshold: 32,
    eagerFlushOnInfer: true,
    eagerFlushOnOutcome: true,
};

function normalizeOptions(options?: InferenceEngineModuleOptions): Required<InferenceEngineModuleOptions> {
    return {
        flushIntervalMs: Math.max(100, Number(options?.flushIntervalMs ?? DEFAULT_OPTIONS.flushIntervalMs)),
        flushOpsThreshold: Math.max(1, Number(options?.flushOpsThreshold ?? DEFAULT_OPTIONS.flushOpsThreshold)),
        eagerFlushOnInfer: options?.eagerFlushOnInfer ?? DEFAULT_OPTIONS.eagerFlushOnInfer,
        eagerFlushOnOutcome: options?.eagerFlushOnOutcome ?? DEFAULT_OPTIONS.eagerFlushOnOutcome,
    };
}

export class InferenceEngineModule implements DaemonModule {
    public enabled = true;
    public readonly manifest = {
        id: 'inference-engine',
        version: '1.1.0',
        description: 'Deterministic inference engine for scoring, ranking, policy tuning, and feedback learning',
        capabilities: ['infer', 'profile', 'recommendations', 'feedback', 'policy'],
    };

    private readonly engine: GICSInferenceEngine;
    private readonly options: Required<InferenceEngineModuleOptions>;
    private ctx: ModuleContext | null = null;
    private flushTimer: ReturnType<typeof setTimeout> | null = null;
    private flushChain: Promise<void> = Promise.resolve();
    private dirtyVersion = 0;
    private flushedVersion = 0;
    private pendingOps = 0;
    private flushCount = 0;
    private lastFlushAt = 0;
    private lastFlushDurationMs = 0;
    private lastDecisionAt = 0;
    private lastOutcomeAt = 0;
    private lastError: string | null = null;
    private readonly profileVersions = new Map<string, number>();
    private readonly publishedProfileVersions = new Map<string, number>();
    private readonly policyVersions = new Map<string, number>();
    private readonly publishedPolicyVersions = new Map<string, number>();
    private readonly pendingDecisionIds = new Set<string>();
    private readonly pendingFeedbackIds = new Set<string>();

    constructor(dataPath: string, private readonly defaultScope: string, options?: InferenceEngineModuleOptions) {
        const statePath = path.join(dataPath, 'inference', 'state.json');
        this.engine = new GICSInferenceEngine(new InferenceStateStore(statePath, defaultScope), defaultScope);
        this.options = normalizeOptions(options);
    }

    async init(ctx: ModuleContext): Promise<void> {
        this.ctx = ctx;
        await this.engine.load();
    }

    async restore(ctx: ModuleContext): Promise<void> {
        this.ctx = ctx;
    }

    async stop(): Promise<void> {
        await this.flushNow('stop');
    }

    async onWrite(event: ModuleWriteEvent, ctx: ModuleContext): Promise<void> {
        if (event.key.startsWith('_infer|') || event.key.startsWith('_sys|')) return;
        this.ctx = ctx;
        this.engine.recordWrite(this.defaultScope, Buffer.byteLength(JSON.stringify(event.fields), 'utf8'));
        this.markProfileDirty(this.defaultScope);
        this.noteMutation();
    }

    async onDelete(event: ModuleDeleteEvent, ctx: ModuleContext): Promise<void> {
        if (event.key.startsWith('_infer|') || event.key.startsWith('_sys|')) return;
        this.ctx = ctx;
        this.engine.recordWrite(this.defaultScope, 0);
        this.markProfileDirty(this.defaultScope);
        this.noteMutation();
    }

    async onRead(event: ModuleReadEvent, ctx: ModuleContext): Promise<void> {
        if (event.key.startsWith('_infer|') || event.key.startsWith('_sys|')) return;
        this.ctx = ctx;
        this.engine.recordRead(this.defaultScope, 0);
        this.markProfileDirty(this.defaultScope);
        this.noteMutation();
    }

    async onScan(_result: unknown, ctx: ModuleContext): Promise<void> {
        this.ctx = ctx;
        this.engine.recordScan(this.defaultScope);
        this.markProfileDirty(this.defaultScope);
        this.noteMutation();
    }

    async onFlush(event: ModuleFlushEvent, ctx: ModuleContext): Promise<void> {
        this.ctx = ctx;
        const compressionRatio = event.bytesWritten > 0 && event.recordsFlushed > 0
            ? Math.max(1, (event.recordsFlushed * 128) / event.bytesWritten)
            : undefined;
        this.engine.recordFlush(this.defaultScope, compressionRatio);
        this.markProfileDirty(this.defaultScope);
        this.markPolicyDirtyByParts('storage.policy', this.defaultScope);
        this.noteMutation();
    }

    async onCompact(_event: ModuleCompactEvent, ctx: ModuleContext): Promise<void> {
        this.ctx = ctx;
        this.engine.recordCompaction(this.defaultScope);
        this.markProfileDirty(this.defaultScope);
        this.noteMutation();
    }

    async onRotate(_event: ModuleRotateEvent, ctx: ModuleContext): Promise<void> {
        this.ctx = ctx;
        this.engine.recordRotation(this.defaultScope);
        this.markProfileDirty(this.defaultScope);
        this.markPolicyDirtyByParts('storage.policy', this.defaultScope);
        this.noteMutation();
    }

    async onOutcome(event: ModuleOutcomeEvent, ctx: ModuleContext): Promise<void> {
        if (!event.domain) return;
        this.ctx = ctx;
        const artifacts = this.engine.recordOutcome(
            event.domain,
            event.decisionId,
            event.context as Record<string, unknown> | undefined,
            event.metrics,
            event.result
        );
        if (!artifacts) return;

        this.markProfileDirty(artifacts.profile.scope);
        if (artifacts.policy) {
            this.markPolicyDirty(artifacts.policy.key);
        }
        this.pendingFeedbackIds.add(artifacts.feedback.feedbackId);
        this.lastOutcomeAt = artifacts.feedback.recordedAt;
        this.noteMutation();

        if (this.options.eagerFlushOnOutcome) {
            await this.flushNow('outcome');
        }
    }

    async infer(request: InferenceRequest, ctx: ModuleContext): Promise<InferenceDecision | null> {
        this.ctx = ctx;
        const artifacts = this.engine.inferDetailed(request);
        this.pendingDecisionIds.add(artifacts.decisionRecord.decisionId);
        this.markProfileDirty(artifacts.profile.scope);
        this.markPolicyDirty(artifacts.policy.key);
        this.lastDecisionAt = artifacts.decision.createdAt;
        this.noteMutation();

        await this.publishDecision(ctx, artifacts.decisionRecord.decisionId);
        await this.publishProfile(ctx, artifacts.profile.scope);
        await this.publishPolicy(ctx, artifacts.policy.key);

        if (this.options.eagerFlushOnInfer) {
            await this.flushNow('infer');
        }
        return artifacts.decision;
    }

    async getProfile(scope: string, ctx: ModuleContext): Promise<Record<string, unknown> | null> {
        this.ctx = ctx;
        this.markProfileDirty(scope);
        await this.publishProfile(ctx, scope);
        if (this.hasDirtyState()) {
            await this.flushNow('getProfile');
        }
        return structuredClone(this.engine.getProfile(scope)) as unknown as Record<string, unknown>;
    }

    async getRecommendations(query: RecommendationQuery): Promise<Array<Record<string, unknown>>> {
        return this.engine.getRecommendations(query);
    }

    async health(): Promise<Record<string, unknown>> {
        return {
            enabled: true,
            defaultScope: this.defaultScope,
            ...this.engine.getRuntimeSnapshot(),
            dirty: this.hasDirtyState(),
            pendingOps: this.pendingOps,
            flushCount: this.flushCount,
            lastFlushAt: this.lastFlushAt,
            lastFlushDurationMs: this.lastFlushDurationMs,
            lastDecisionAt: this.lastDecisionAt,
            lastOutcomeAt: this.lastOutcomeAt,
            lastError: this.lastError,
            flushIntervalMs: this.options.flushIntervalMs,
            flushOpsThreshold: this.options.flushOpsThreshold,
            pendingProfiles: Array.from(this.profileVersions.entries()).filter(([scope, version]) => this.publishedProfileVersions.get(scope) !== version).length,
            pendingPolicies: Array.from(this.policyVersions.entries()).filter(([key, version]) => this.publishedPolicyVersions.get(key) !== version).length,
            pendingDecisions: this.pendingDecisionIds.size,
            pendingFeedback: this.pendingFeedbackIds.size,
        };
    }

    async snapshot(): Promise<Record<string, unknown>> {
        return this.health();
    }

    async forceFlush(): Promise<void> {
        await this.flushNow('manual');
    }

    private noteMutation(): void {
        this.dirtyVersion += 1;
        this.pendingOps += 1;
        if (this.pendingOps >= this.options.flushOpsThreshold) {
            void this.flushNow('threshold').catch(() => undefined);
            return;
        }
        this.scheduleFlush();
    }

    private scheduleFlush(): void {
        if (this.flushTimer) return;
        this.flushTimer = setTimeout(() => {
            this.flushTimer = null;
            void this.flushNow('timer').catch(() => undefined);
        }, this.options.flushIntervalMs);
    }

    private clearScheduledFlush(): void {
        if (!this.flushTimer) return;
        clearTimeout(this.flushTimer);
        this.flushTimer = null;
    }

    private hasDirtyState(): boolean {
        return this.dirtyVersion !== this.flushedVersion
            || this.pendingDecisionIds.size > 0
            || this.pendingFeedbackIds.size > 0
            || Array.from(this.profileVersions.entries()).some(([scope, version]) => this.publishedProfileVersions.get(scope) !== version)
            || Array.from(this.policyVersions.entries()).some(([key, version]) => this.publishedPolicyVersions.get(key) !== version);
    }

    private async flushNow(reason: string): Promise<void> {
        const run = async () => {
            this.clearScheduledFlush();
            while (this.hasDirtyState()) {
                const targetVersion = this.dirtyVersion;
                const startedAt = Date.now();
                if (this.ctx) {
                    await this.publishPendingArtifacts(this.ctx);
                }
                await this.engine.save();
                this.flushedVersion = targetVersion;
                this.pendingOps = this.dirtyVersion === this.flushedVersion ? 0 : this.pendingOps;
                this.flushCount += 1;
                this.lastFlushAt = Date.now();
                this.lastFlushDurationMs = this.lastFlushAt - startedAt;
                this.lastError = null;
                if (!this.hasDirtyState()) break;
            }
        };

        this.flushChain = this.flushChain.then(run, async () => {
            await run();
        });

        try {
            await this.flushChain;
        } catch (err: any) {
            this.lastError = `${reason}: ${err.message}`;
            throw err;
        }
    }

    private markProfileDirty(scope: string): void {
        this.profileVersions.set(scope, (this.profileVersions.get(scope) ?? 0) + 1);
    }

    private markPolicyDirty(policyKey: string): void {
        this.policyVersions.set(policyKey, (this.policyVersions.get(policyKey) ?? 0) + 1);
    }

    private markPolicyDirtyByParts(domain: string, scope: string, subject?: string): void {
        const policy = this.engine.getPolicy(domain, scope, subject);
        if (policy) {
            this.markPolicyDirty(policy.key);
        }
    }

    private async publishPendingArtifacts(ctx: ModuleContext): Promise<void> {
        const pendingProfiles = Array.from(this.profileVersions.entries())
            .filter(([scope, version]) => this.publishedProfileVersions.get(scope) !== version)
            .map(([scope]) => scope);
        for (const scope of pendingProfiles) {
            await this.publishProfile(ctx, scope);
        }

        const pendingPolicies = Array.from(this.policyVersions.entries())
            .filter(([policyKey, version]) => this.publishedPolicyVersions.get(policyKey) !== version)
            .map(([policyKey]) => policyKey);
        for (const policyKey of pendingPolicies) {
            await this.publishPolicy(ctx, policyKey);
        }

        for (const decisionId of Array.from(this.pendingDecisionIds)) {
            await this.publishDecision(ctx, decisionId);
        }

        for (const feedbackId of Array.from(this.pendingFeedbackIds)) {
            await this.publishFeedback(ctx, feedbackId);
        }
    }

    private async publishProfile(ctx: ModuleContext, scope: string): Promise<void> {
        const profile = this.engine.getProfile(scope);
        await ctx.upsertSystemRecord(`_infer|profile|${scope}`, {
            scope,
            version: profile.version,
            updated_at_ms: profile.updatedAt,
            profile_json: JSON.stringify(profile),
        });
        const version = this.profileVersions.get(scope);
        if (version !== undefined) {
            this.publishedProfileVersions.set(scope, version);
        }
    }

    private async publishPolicy(ctx: ModuleContext, policyKey: string): Promise<void> {
        const policy = this.engine.getPolicyByKey(policyKey);
        if (!policy) return;
        await ctx.upsertSystemRecord(policy.systemKey, {
            domain: policy.domain,
            scope: policy.scope,
            subject: policy.subject ?? '',
            policy_version: policy.policyVersion,
            profile_version: policy.profileVersion,
            generated_at_ms: policy.generatedAt,
            recommended_candidate_id: policy.recommendedCandidateId ?? '',
            basis_json: JSON.stringify(policy.basis),
            weights_json: JSON.stringify(policy.weights),
            thresholds_json: JSON.stringify(policy.thresholds),
            payload_json: JSON.stringify(policy.payload),
            evidence_json: JSON.stringify(policy.evidenceKeys),
        });
        const version = this.policyVersions.get(policyKey);
        if (version !== undefined) {
            this.publishedPolicyVersions.set(policyKey, version);
        }
    }

    private async publishDecision(ctx: ModuleContext, decisionId: string): Promise<void> {
        const decision = this.engine.getDecision(decisionId);
        if (!decision) return;
        await ctx.upsertSystemRecord(decision.systemKey, {
            domain: decision.domain,
            scope: decision.scope,
            subject: decision.subject ?? '',
            decision_id: decision.decisionId,
            recommended_id: decision.recommendedId ?? '',
            policy_key: decision.policyKey,
            policy_version: decision.policyVersion,
            profile_version: decision.profileVersion,
            created_at_ms: decision.createdAt,
            ranking_json: JSON.stringify(decision.ranking),
            evidence_json: JSON.stringify(decision.evidenceKeys),
        });
        this.pendingDecisionIds.delete(decisionId);
    }

    private async publishFeedback(ctx: ModuleContext, feedbackId: string): Promise<void> {
        const feedback = this.engine.getFeedback(feedbackId);
        if (!feedback) return;
        await ctx.upsertSystemRecord(feedback.systemKey, {
            domain: feedback.domain,
            scope: feedback.scope,
            subject: feedback.subject ?? '',
            feedback_id: feedback.feedbackId,
            decision_id: feedback.decisionId ?? '',
            candidate_id: feedback.candidateId,
            success: feedback.success ? 1 : 0,
            result: feedback.result,
            recorded_at_ms: feedback.recordedAt,
            metrics_json: JSON.stringify(feedback.metrics),
            context_json: JSON.stringify(feedback.context ?? {}),
        });
        this.pendingFeedbackIds.delete(feedbackId);
    }
}
